window.__LIBQ=window.__LIBQ||{};window.__LIBQ["tien-nghich"]=window.__LIBQ["tien-nghich"]||{};window.__LIBQ["tien-nghich"]["q08"]=window.__LIBQ["tien-nghich"]["q08"]||{};window.__LIBQ["tien-nghich"]["q08"]["cotTruyen"]=[{"chuong":888,"tieuDe":"Tư Cách","tomTat":"Vương Lâm đem bình tro cốt của Tôn Thái chôn xuống đất, dựng bia “Tôn Thái chi mộ” và từ cái chết tha hương ấy cảm khái về sinh tử, tu đạo cùng nỗi mong cầu đời phàm của người đã bước lên tiên lộ. Sau đó hắn tới vùng đình chiến phía Tây và phía Bắc Liên Minh, nơi Liệt Vân Tử của La Thiên đang trấn giữ một tu chân tinh gần chiến trường cũ bằng mười ba huyết cầu La Phù. Hứa Đình, kẻ từng bị tưởng đã chết trong đại chiến, xuất hiện bên cạnh Liệt Vân Tử và bộc lộ sát khí khi gặp Vương Lâm. Vương Lâm chỉ dùng ánh mắt và một tiếng quát đã khiến Hứa Đình tâm thần chấn động, phun máu, nhờ đó khiến Liệt Vân Tử phải nhìn nhận hắn bằng tư cách khác. Khi Liệt Vân Tử lấy Đệ Nhị Phúc Chiến Tự Thiếp ra theo lời hứa cũ, Vương Lâm không mở ngay mà dùng thế vừa tạo để đòi một La Phù làm điều kiện. Liệt Vân Tử sau khi nghe Vương Lâm nhắc tới cuộc hẹn với sư huynh thì chấp nhận giao một huyết cầu. Cuối cùng Vương Lâm ném Đệ Nhị Phúc cho Hứa Đình xem trước, khiến chiến ý trong tranh bùng lên như hung thú phá phong ấn và lao thẳng về phía Hứa Đình."},{"chuong":889,"tieuDe":"Bức Tranh Chữ “Chiến” Huyền Bí","tomTat":"Hứa Đình thử mở Chiến Tự Thiếp Đệ Nhị Phúc, dốc sức kéo đến bảy phần nhưng bị sương đen trong tranh hóa thành thú linh lao ra thôn phệ, khiến hắn phun máu và tiên nguyên tổn hại nặng. Liệt Vân Tử đánh giá Hứa Đình dù thất bại vẫn là người xuất sắc, rồi đưa bức tranh cho Vương Lâm dưới thân phận Hứa Mộc thử mở. Vương Lâm nhận ra bản nguyên Hứa Đình từng thu được từ Đệ Nhất Lôi—Chiến Thiếp đã bị thú linh hút mất, từ đó càng nghi ngờ dụng ý của Liệt Vân Tử. Khi Vương Lâm mở đến bảy phần, thú linh lại lao ra nhưng bị hắn dùng khí tức Cổ Thần Vương Tộc Ngũ Tinh quát lui. Vương Lâm mở hoàn toàn bức tranh, nhìn thấy chữ Chiến tỏa khí tức tang thương và chìm vào ý cảnh truyền thừa của một lão giả áo trắng tự xưng đã đạt Không Chi ba vạn năm trước. Lão giả nói mình để lại Chiến Tự Lục Thiếp, người đời sau nếu thu đủ sẽ trở thành truyền nhân. Liệt Vân Tử ném Hứa Đình ra xa để hỏi riêng, rồi khi nghe Vương Lâm nói hai chữ truyền thừa, lão lập tức liên hệ chuyện này với sự mất tích của Tiên Tổ Chiến Tinh."},{"chuong":890,"tieuDe":"U Minh Dẫn Lộ","tomTat":"Liệt Vân Tử nhớ lại bí mật Đệ Tam Phúc Chiến Tự Thiếp: tiên tổ Chiến Tinh từng nghiên cứu bức tranh, bế quan nghìn năm rồi mất tích, chỉ để lại bức tranh và một khối ngọc giản. Lão đưa Đệ Tam Phúc cho Vương Lâm, hứa đáp ứng mọi yêu cầu, nhưng Vương Lâm vừa chạm tay đã cảm nhận nguy hiểm chí tử nên lập tức từ chối mở tranh. Liệt Vân Tử cân nhắc ép buộc nhưng tạm buông vì kiêng dè Viêm Lôi Tử và đặc biệt là Thanh Thủy, ngoài mặt hứa hẹn hậu thưởng còn trong lòng chờ cơ hội sau khi Thanh Thủy chết. Vương Lâm rời đi, tự nhận chuyến này tuy mạo hiểm nhưng giúp hắn hiểu lai lịch Chiến Tự Thiếp, có thêm lực lượng bản nguyên và lấy được huyết cầu La Phù. Vài ngày sau trong tinh không, Thanh Thủy xuất hiện với hơn trăm đầu lâu tu sĩ Sát Vực Giới, dùng Tiên Thuật U Minh và U Minh Dẫn Lộ nghiền tàn hồn, gom ký ức cùng ý niệm của họ thành hắc động dẫn đường. Thanh Thủy và Vương Lâm tiến vào Sát Vực Giới, nơi hiện ra như một thế giới màu đỏ đầy kiến trúc hình kiếm, tháp lớn và xích đen. Thanh Thủy tuyên bố đến lấy vật cũ và diệt giới, sát khí bùng phát làm nhiều kiến trúc vỡ nát, còn Vương Lâm nhận ra đây là một trong Bát Giới của Tu Chân Liên Minh."},{"chuong":891,"tieuDe":"Sát Vực Giới","tomTat":"Sát Vực Giới được giới thiệu là một trong Bát Giới của Tu Chân Liên Minh, hình thành từ khe nứt không gian còn sót sau khi Vũ Tiên Giới tan vỡ. Nơi này có chín mươi chín Kình Thiên Kiếm, chín mươi chín tu sĩ hạch tâm cùng hệ thống đệ tử bên ngoài và chính phó giới chủ, nổi danh như con dao đối ngoại chuyên xử lý kẻ không chịu giao mệnh hồn. Thanh Thủy đánh thẳng vào Sát Vực Giới, khiến các kiến trúc đại kiếm sụp đổ và phá vỡ tiền lệ gần như chưa từng có ai giết tới tận nhà. Hắn giao đám tu sĩ hắc y cho Vương Lâm, để Vương Lâm dùng thân thể Cổ Thần, Súc Địa Thành Thốn và chỉ kiếm nghiền ép các tu sĩ Sát Vực Giới. Vương Lâm đoạt phi kiếm bản mệnh, phá ngọc giản tự bạo, giết tu sĩ Khuy Niết trung kỳ và nhận ra bản thân đã bước vào hàng cường giả chân chính sau khi thành Ngũ Tinh Vương Tộc Cổ Thần. Ở tháp trung tâm, phó giới chủ Sát Vực Giới phân thân tìm đường thoát qua khe nứt hư vô, nhưng Thanh Thủy gọi tám Hắc Long, thi triển Đóng Băng Thiên Địa phong tỏa toàn bộ đường lui. Cuối chương, Thanh Thủy phá tháp, kéo lão già khỏi khe nứt và ném xuống phía dưới, đặt phó giới chủ vào thế bị khống chế."},{"chuong":892,"tieuDe":"Khuất Phục Cho Ta","tomTat":"Sau khi tháp cao trong Sát Vực Giới sụp đổ, tử quang tách làm hai, một đạo đánh về Vương Lâm, một đạo xuyên qua lão nhân áo đen khiến thân thể và nguyên thần lão tan vỡ rồi lao tới Thanh Thủy. Thanh Thủy dùng Cực Cảnh đối kháng, buộc tử quang hiện thành Lăng Vân Tử, Giới Chủ Sát Vực Giới, người nhận ra Cực Cảnh của Thanh Thủy liên quan di vật thê tử mình và quyết ý giao chiến bằng chỗ dựa là Không Niết pháp bảo trấn giới. Ở phía Vương Lâm, đạo tử quang chứa Cực Cảnh bị hắn vận Cổ Thần Tinh Điểm hóa ra Diệt Thần Mâu hư ảo phá tan, khiến hắn xác nhận pháp khí Vương tộc Cổ Thần có thể chống Cực Cảnh. Gần trăm tu sĩ Sát Vực Giới còn sống niệm chú triệu mười một đạo tinh quang chứa phi kiếm bạc truy kích Vương Lâm; hắn nhận ra bộ kiếm này cùng thời rèn luyện, nếu gom đủ chín mươi chín thanh thì có thể làm chỗ dựa đối đầu Lăng Thiên Hậu. Ba cường giả Sát Vực Giới tiếp tục vây công: lão nhân Khuy Niết hậu kỳ dùng bốn Bạch Ngọc Hồ Lô gọi Bảo Hồ Lô Tiên, một tu sĩ Khuy Niết trung kỳ thi triển Vạn Quân Chi Thủy, người còn lại dùng Hóa Huyết Tiên Võng. Trước vòng vây, Vương Lâm mở Phong Tiên Ấn mười tám tầng địa ngục, thả vô số oan hồn rồi thi triển Tát Đậu Thành Binh để cản công kích xung quanh. Hắn dùng bàn tay Cổ Thần bắt một đạo tinh quang, bị tàn hồn phản phệ thì hiện nguyên thần Thái Cổ Lôi Long, dẫn lôi đình khắp Sát Vực Giới trấn áp tàn hồn. Cuối cùng tinh quang tan vỡ, lộ ra trường kiếm bạc dài bảy thước khắc chữ “Chín”, và thanh kiếm này khuất phục Vương Lâm."},{"chuong":893,"tieuDe":"Tung Tích Tịch Niết","tomTat":"Vương Lâm tiếp tục đoạt phi kiếm giữa chiến trường Sát Vực giới, đóng lạc ấn thần thức lên trường kiếm bảy thước rồi phong ấn một thanh kiếm đang giãy dụa và ném vào túi trữ vật. Chín thanh phi kiếm còn lại hợp nhất thành đại kiếm mang khí âm hàn phản công, đồng thời Huyễn Hư Tử, một nam tử trung niên áo bào đỏ, từ ánh sáng đỏ sậm lộ diện và điều động bốn nữ nhân từ Bạch Ngọc Hồ Lô tập kích hắn. Vương Lâm dùng Hô Phong hóa ba hắc long cản địch, nhận ra khí tức đối phương vượt xa Khuy Niết và phán đoán đây là tu sĩ Tịnh Niết sơ kỳ, nên quyết định dùng trận này để kiểm chứng thực lực hiện tại. Huyễn Hư Tử thi triển Hồng Trạch Hoang Sa, lấy nguyên lực thiên địa hóa thành cát đen rồi dùng quy tắc ảo biến ảo pháp thành cánh tay khổng lồ đối oanh Cổ Thần quyền của Vương Lâm, khiến dư ba cuốn chết một số tu sĩ gần đó. Khi Vương Lâm bị chấn lui, Thần Ma Tử, một lão nhân áo xanh vốn ẩn nấp vì kiêng kị Thanh Thủy, hiện thân và xem lúc Huyễn Hư Tử đấu với Hứa Mộc là cơ hội lập công. Hắn nhiễu loạn sức mạnh thiên địa xung quanh để khóa Súc Địa Thành Thốn và định đánh lén Vương Lâm, nhưng đúng lúc ấy mây tím trên trời sinh biến, bảy bóng dáng màu tím rơi xuống rồi tan vỡ dần, cuối cùng chỉ còn lại một bóng."},{"chuong":894,"tieuDe":"Trâm Cài Tóc","tomTat":"Sát Vực Giới giới chủ hiện thân trong thân thể màu tím nhưng đã bị thương và kinh hãi trước Thanh Thủy. Tia chớp Cực Cảnh của Thanh Thủy không đánh giới chủ mà xuyên qua Thần Ma Tử, giết chết hắn rồi quét sạch phần lớn tu sĩ chung quanh. Thanh Thủy thu sương tím, để lộ chiếc trâm cài tóc màu tím của Hàm Yên, sau đó lạnh lùng tuyên bố vùng đất hắn muốn đồ sát tuyệt không giữ người sống. Giới chủ Sát Vực Giới tự phá tay mở khe bỏ trốn nhưng bị Tiên Thuật Băng Sơn chặn lại, còn Huyễn Hư Tử bỏ đấu pháp với Vương Lâm và ném chín kiếm để thoát thân. Ba lần Băng khiến dung nham, bụi độc và núi sụp phủ khắp Sát Vực Giới, làm tu sĩ và kiến trúc trong giới gần như bị diệt sạch. Thanh Thủy thu mười tám đạo ngân quang ném cho Vương Lâm, bắt Huyễn Hư Tử cùng giới chủ Sát Vực Giới làm nô rồi từ biệt Hứa Mộc. Vương Lâm rời Sát Vực Giới đang sụp đổ, xuất hiện trong tinh không và hướng tới Thiên Vận tinh nơi Na Di ở. Thanh Thủy nhìn trâm cài tóc, nhớ lại Hàm Yên và bi kịch năm xưa, rồi hứa sẽ tìm ra nguyên nhân tất cả."},{"chuong":895,"tieuDe":"Thiếu Gia","tomTat":"Sau khi rời khỏi hư vô, Vương Lâm không vội tới Thiên Vận tinh mà dùng cảm ứng tâm thần tìm Lôi Cát, Đại Đầu và Tháp Sơn. Ở phương đông xa xôi, hắn tìm thấy Tháp Sơn đang ẩn trong một mảnh vụn tu chân tinh, gọi hắn hiện thân rồi thu về phía sau mình. Trên đường đi, Vương Lâm suy ngẫm về uy lực Sơn Băng thuật của Bạch Phàm và nảy ý muốn một ngày nào đó tự sáng tạo thần thông riêng. Cùng lúc đó, Lôi Cát trọng thương vẫn cõng Đại Đầu đang trúng thủ ấn màu đen, kiên quyết không bỏ rơi người đã vì cứu mình mà bị thương. Phía sau họ, một thiếu gia áo lam tà dị ngồi trên đầu người khổng lồ truy sát, tuyên bố đã nhìn trúng thân thể hoàng tộc Cự Ma Tộc của Lôi Cát. Khi hắn phun hạt anh đào hóa thành bộ xương khô màu lục định đánh vào xương sống Lôi Cát, bàn tay của Vương Lâm từ hư vô vươn ra bóp nát công kích. Vương Lâm hiện thân, lạnh giọng chất vấn kẻ đã đả thương tọa kỵ và tùy tòng của mình, khiến Lôi Cát cùng Đại Đầu kinh hỉ nhận ra chủ nhân."},{"chuong":896,"tieuDe":"Đệ Tử Nội Tông Thi Âm Tông","tomTat":"Vương Lâm bước ra từ sóng gợn, không để ý đối thủ mà lập tức kiểm tra thương thế của Lôi Cát và Đại Đầu. Thấy Đại Đầu bị độc thủ ấn làm tử khí xâm thân, hắn truyền nguyên lực, ép máu đen và hắc khí ra ngoài, rồi đánh tan năm tàn hồn trong thủ ấn để khôi phục sinh cơ cho Đại Đầu. Thanh niên áo lam sai Tôn Cẩu Tử, kẻ đã đoạt xá thân thể Cự Ma Tộc, dùng thủy hệ thần thông hóa hải long tấn công, nhưng bị Vương Lâm phất tay phá tan và kéo nguyên thần ra khỏi thân thể. Thanh niên áo lam ném anh đào hóa mũi xương khô để cứu thuộc hạ, song Vương Lâm dùng thân thể Cự Ma Tộc làm vật chắn khiến thân thể ấy tan nát và bị hút sạch huyết nhục. Khi bị áp sát, thanh niên áo lam tự xưng là nội tông đệ tử Thi Âm Tông, giả vờ cầu hòa rồi dùng Ngũ quỷ âm thần Chuyển Luân không đánh lén nhưng vẫn bị phá tan. Hắn ép đại hán Cự Ma Tộc thứ hai thi triển thiên phú tạo lốc xoáy rút lui, còn đại hán tự bạo nguyên thần để chặn truy kích. Trước lực tự bạo đang quét tới, Vương Lâm lấy Xạ Thần Xa thứ ba đã lâu không dùng, pháp bảo hóa thành một con bướm nhiều màu."},{"chuong":897,"tieuDe":"Phấn Y Nữ Tử","tomTat":"Con bướm nhiều màu dùng ba lần vỗ cánh khiến lực tự bạo biến đổi theo quy tắc, cuộn ngược vào lốc xoáy đang co rút và làm bên trong truyền ra tiếng hét thảm. Thanh niên áo lam không chết mà nguyên thần trọng thương trở về một hồn hải bí mật trong Liên Minh Tinh Vực, được lão nhân âm trầm gọi là ông nội cứu lấy; Vương Lâm nhận ra ô quang trên người hắn đã hóa giải một nửa công kích. Sau đó Vương Lâm xóa lục mang tàn hồn trên người Lôi Cát, cùng Đại Đầu cưỡi thân hình khổng lồ của Lôi Cát đi mười ngày tới gần Thiên Vận tinh. Trước nguy cơ ở Thiên Vận tinh, hắn căn dặn Đại Đầu và Lôi Cát tìm nơi ẩn nấp, còn mình một mình tiến vào phạm vi thế lực cũ. Trên đường, Vương Lâm suy tính lệnh bài tiên phủ, Thiên Vận Tử, thân phận Tứ Thánh Tông, tam nhãn, căn nguyên lực, năm tinh điểm Cổ Thần và chu tước ấn ký. Bên ngoài Thiên Vận Tông, Lăng Thiên Hậu dẫn đệ tử Đại La Kiếm Tông cùng nhiều đại thần thông giả tới chờ Thiên Vận Tử nói rõ thiên cơ liên quan Vương Lâm và lệnh bài tiên phủ. Thiên Vận Tử bình tĩnh đứng trên quảng trường, mỉm cười báo rằng Vương Lâm đã tới, khiến mọi ánh mắt hướng về chân trời và phấn y tiên tử tò mò về người từng danh chấn Triều Tịch."},{"chuong":898,"tieuDe":"Tiến Tới","tomTat":"Tại quảng trường Thiên Vận Tông, nhiều người từng biết hoặc nghe danh Vương Lâm cùng dõi về chân trời, trong đó có Bạch Vi, Triệu Tinh Sát, tứ sư tỷ Tử hệ và Tư Mã Như Phong. Vương Lâm mặc áo trắng xuất hiện, khí độ và ấn ký mi tâm khiến Lăng Thiên Hậu cùng các lão quái chú ý, mỹ phụ thôn nữ trung niên còn nhận ra Chu tước ấn ký. Hắn bình tĩnh hành lễ với Thiên Vận Tử, được Thiên Vận Tử nhận là đệ tử và yêu cầu trả lời chuyện các tiền bối truy hỏi. Môn hạ Đại La Kiếm Tông chất vấn chuyện Yêu Linh Chi Địa nhưng bị Vương Lâm phản kích bằng lời, còn Lăng Thiên Hậu công khai xác nhận Vương Lâm đã đạt Khuy Niết sơ kỳ khiến toàn trường chấn động. Các lão quái tiếp tục truy hỏi về chuyện năm đó, Huyết Tổ và lệnh bài tiên phủ, Vương Lâm thừa nhận mình từng chiếm được một lệnh bài. Lăng Thiên Hậu lập tức phóng kiếm khí công kích Vương Lâm, Vương Lâm dùng một quyền lốc xoáy đen nghênh đỡ, nhưng Thiên Vận Tử phất gió bảy màu hóa giải cả hai bên và cảnh cáo Lăng Thiên Hậu không được ra tay với đệ tử của mình trong sơn môn. Cuối chương, Lăng Thiên Hậu chuyển sang đối đầu Thiên Vận Tử và để bốn thanh nguyên thần chi kiếm xuất hiện sau lưng."},{"chuong":899,"tieuDe":"Tán Thành","tomTat":"Thiên Vận Tử công khai khẳng định Vương Lâm vẫn là đệ tử Thiên Vận Tông nếu chưa chính thức rời sư môn, còn Lăng Thiên Hậu lấy ân oán Kiếm Tiếu thập nhị tử để buộc Vương Lâm tiếp ba đạo kiếm khí. Vương Lâm bình tĩnh nhận chiến, dùng thân thể và cổ thần lực đánh tan đạo kiếm khí đầu, khiến các lão quái bắt đầu nhìn lại thực lực thật của hắn. Khi Lăng Thiên Hậu tiếp tục ra tay, Vương Lâm gọi Tam Cửu Chi Kiếm, rồi tăng thành Ngũ Cửu Kiếm Trận, dung nhập Trảm La quyết để đối kháng Minh kiếm — Huyết Chú Kiếm. Trận giao phong khiến thiên địa biến sắc, dư lực lớn đến mức Thiên Vận Tử phải ngăn để tránh Thiên Vận Tinh bị ảnh hưởng nặng. Sau va chạm, Lăng Thiên Hậu tuy không bị thương nhưng thừa nhận thực lực của Vương Lâm, tuyên bố xóa bỏ ân oán Đại La Kiếm Tông và từ bỏ tranh lệnh bài. Các lão quái lần lượt rời đi, Kỳ Mộng Đàm mời Vương Lâm tới Mộng Tinh, mỹ phụ luyện khí mời hắn tới Tử Hà Tinh, còn Thiên Cầm âm thầm nhớ lại ân cứu mạng năm xưa. Khi chỉ còn hai thầy trò, Vương Lâm nói muốn vào Yêu Linh Chi Địa; Thiên Vận Tử xác nhận hắn có tư cách nhờ thân phận chính phẩm Lôi Tiên La Thiên và danh sách Chu Tước thuộc Tứ Thánh Tông. Thiên Vận Tử còn tiết lộ danh sách Chu Tước tính cả Vương Lâm chỉ có ba người, khiến Vương Lâm âm thầm chú ý dù bề ngoài vẫn bình thường."},{"chuong":900,"tieuDe":"Bí Mật Thiên Vận Tử","tomTat":"Thiên Vận Tử cho biết việc mở Yêu Linh Chi Địa còn cần chuẩn bị, lần này rất trọng yếu nên sẽ mời thêm hảo hữu vào động phủ, rồi bảo Vương Lâm ở lại Thiên Vận Tông chờ. Sau khi Thiên Vận Tử rời đi và nhắc Tử Lâm Các Thủy vẫn giữ cho hắn, Vương Lâm suy xét lại Lăng Thiên Hậu cùng những điểm khó đoán của Thiên Vận Tử, cảm thấy mọi manh mối đều không đủ để nhìn thấu đối phương. Trên đường trở về Tử hệ, hắn nghe hai đệ tử Thiên Vận Tông bàn về Quỷ Nhãn phường thị sắp mở lại, nơi từng đấu giá tiên thuật đầy đủ và lần này cũng có vật thần bí. Nam tử áo lam họ Lý nhận ra Vương Lâm, khiếp sợ trước thân phận lão thất Tử hệ năm xưa và kể với sư muội về lời đồn ma đầu Yêu Linh Chi Địa. Vương Lâm trở lại Tử Phong và Tử Lâm Các, thấy lầu các phủ bụi nhưng bài trí vẫn như cũ, bèn dùng gió cuốn sạch bụi mà không làm động vật dụng. Khi thắp lại ngọn đèn dầu, hắn nhìn ánh lửa bị gió núi thổi chập chờn và hiểu ra Thiên Vận Tử có thể giống như vô số phân thân cùng tồn tại trong một thân thể, liên tục luân phiên hiện ra nên mỗi lần gặp đều khác nhau."},{"chuong":901,"tieuDe":"Căn Nguyên Ban Đầu","tomTat":"Trong phòng trên Tử Phong, Vương Lâm quan sát ánh nến lay động và thử đóng kín cửa để cắt gió núi, nhưng ánh nến vẫn không hoàn toàn yên ổn. Từ hiện tượng ấy, hắn liên hệ tới Thiên Vận Tử, cho rằng muốn nhìn ra hình dạng ban đầu của một biến hóa khó lường thì không thể chỉ chặn ngoại lực bên ngoài. Đêm khuya, hắn bay lên trời, dùng cảm ngộ quy tắc mưa tản mây để ánh trăng chiếu rõ Tử Phong, rồi từ cỏ cây, gió và bóng núi ngộ ra núi vốn không động, cái động là do tâm mình động. Trở lại phòng, hắn nhìn ánh nến như bị cố định, thấy nó hóa thành cảnh tượng núi lửa do một chỉ của mình tạo ra, rồi tiếp tục nhìn sâu tới vô số điểm nguyên lực vận hành theo trật tự của Hỏa chi quy tắc. Khi định xâm nhập sâu hơn, các điểm nguyên lực phóng đại mãnh liệt, thân thể và tam nhãn của hắn không chịu nổi khiến hắn tỉnh lại trong mồ hôi lạnh. Sau đó Vương Lâm phỏng đoán tầng mình thoáng thấy chính là căn nguyên, thứ hiện tại hắn chỉ có thể chạm tới trong khoảnh khắc. Đến rạng sáng, hắn điều tức mở mắt thì nghe giọng một người ngoài lầu gọi lão thất và xin vào."},{"chuong":902,"tieuDe":"Vương Lâm Xấu Hổ","tomTat":"Triệu Hân Mộng mặc áo tím vào phòng Vương Lâm, âm thầm dùng thần thức dò xét nhưng lập tức bị ánh mắt hắn khóa lại, khiến nàng hiểu chỉ cần động là có thể bị thôn phệ. Vương Lâm nhìn ra trong cơ thể nàng có sáu đạo phong ấn, nhờ đó tu vi thật bị ép xuống mức bên ngoài chỉ khoảng Anh Biến hậu kỳ. Triệu Hân Mộng tiết lộ đệ tử Thiên Vận Tông nếu vượt Vấn Đỉnh đại viên mãn tới Âm Hư thì không quá một năm sẽ mất tích, vì vậy nhiều đồng môn tự phong ấn tu vi và nàng cũng bị Thiên Vận Tử nắm mệnh hồn. Nàng nêu Tôn Hồng, Lô Hải và Nhất Tử làm ví dụ, rồi cầu xin Vương Lâm giúp phong ấn vĩnh viễn để tránh kết cục bị mất tích hoặc bị thôn phệ như lời đồn về sư tôn. Khi phát hiện Bạch Vi tới, Triệu Hân Mộng ẩn thân trên giường Vương Lâm, tạo tình huống khiến hắn khó xử. Bạch Vi vào gặp, xác nhận mình vốn là nữ nhân và yêu cầu hắn gọi là sư muội, làm Vương Lâm hiếm khi xấu hổ. Sau đó Bạch Vi nghiêm túc cảnh báo hắn không nên trở về, đề nghị cùng tới Quỷ Nhãn phường thị trên Thiên Vận Tinh để nói rõ hơn. Vương Lâm nhận ra nàng không có phong ấn, tu vi thật là Anh Biến trung kỳ, rồi hẹn trưa nay gặp ở chân núi Tử phong."},{"chuong":903,"tieuDe":"Hứa Lập Quốc Thích Nhất","tomTat":"Sau khi Bạch Vi rời đi, Hứa Lập Quốc trong túi trữ vật lập tức truyền âm cho Vương Lâm, liên tục tán thưởng nàng và xin được ra ngoài. Triệu Hân Mộng hiện thân cầu Vương Lâm gia cố phong ấn, thậm chí nguyện dùng nguyên âm ngàn năm để trao đổi, khiến hắn nhận ra chuyện này có thể liên quan tới dụng ý của Thiên Vận Tử. Vương Lâm thả Hứa Lập Quốc ra khỏi kiếm tiên, dùng ánh mắt và uy áp ép ma đầu này đổi giọng nịnh bợ, rồi cho phép hắn tạm ở ngoài để kế thừa kiếm ý nhưng trong lòng đã quyết định sẽ tế luyện lại. Hứa Lập Quốc ngoài mặt thuận phục, bên trong vẫn bất mãn, nhớ tới thời đi theo Ma tộc lão tổ và càng khao khát thoát khỏi khống chế. Đến trưa, Vương Lâm xuống chân Tử Phong gặp Bạch Vi; Hứa Lập Quốc si mê nàng đến mức lao ra, lập tức bị Vương Lâm chộp thẳng linh hồn trấn áp. Bạch Vi tế phi kiếm dẫn đường đi phường thị, còn Vương Lâm vừa nhận ra âm khí của nàng nặng hơn năm xưa vừa phát hiện Triệu Hân Mộng vẫn âm thầm theo sau."},{"chuong":904,"tieuDe":"Trần Đạo Tam Tử","tomTat":"Trên đường phi hành tới Quỷ Nhãn Thành, Vương Lâm nhận ra Bạch Vi có âm khí lưu chuyển trong cơ thể cùng tâm tính, hành vi nữ tính bất thường nhưng chưa xác định được vấn đề. Bạch Vi kể về khí hậu Thiên Vận Tinh, mấy trăm năm ít biến cố của Thiên Vận Tông, chuyện hoa Bạch Dương Mộc sau núi nở màu đen rồi hóa sương, và danh tiếng Quỷ Nhãn Thành nhờ từng bán đấu giá một bộ tiên thuật đầy đủ. Khi bị hỏi công pháp, Bạch Vi phản ứng gay gắt rồi thừa nhận tu Song Dục Tiên Quyết, khiến Vương Lâm thấy âm khí kết thành ấn ký kỳ dị và lặng lẽ ghi nhớ. Tới ngoài thành trì hình tròn, Vương Lâm dùng thần thức lướt nhẹ dò cấm chế thì bị ba đạo thần thức của Trần Đạo Tam Tử bùng lên vây khốn. Một thần niệm tự xưng Trần Nhất Tử ép hắn nhận sai rời đi, cho ba giây suy xét rồi cùng hai thần thức hóa cự long định cắn nuốt thần thức hắn. Vương Lâm không nhượng bộ, bước thẳng vào thành khiến cấm chế tan vỡ, dùng tay trái bắt một cự long ném vỡ, làm lão nhân áo xanh trong thành phun máu và kinh hãi gọi hắn là Tịnh Niết lão quái."},{"chuong":905,"tieuDe":"Hóa Thù Thành Bạn","tomTat":"Vương Lâm dùng thân thể và thần thức phản kích cực nhanh, một quyền hư không đánh tan cự long do thần thức ba người Trần Đạo Tam Tử hợp thành, khiến người đàn ông trung niên áo tím bị phản chấn thổ huyết và nghi hắn là Tịnh Niết. Hắn còn kéo đạo thần thức cuối cùng của Nhất Trần Tử tới bóp nát, buộc ba người phải hiện thân. Nhận ra thủ đoạn đối phương vượt xa Khuy Niết, ba huynh đệ hạ giọng xin lỗi; Vương Lâm cũng nói mình quấy nhiễu trước rồi bỏ qua, đúng mạch hóa thù thành bạn. Nhất Trần Tử nhắc bình Tử Ngọc Dịch sắp đấu giá và mời Vương Lâm lưu lại nơi tạm cư của ba người, hắn đồng ý rồi gọi Bạch Vi cùng Hứa Lập Quốc đi theo. Vào phòng thanh tĩnh, Vương Lâm nhớ lại những lời vụn vặt của Bạch Vi cùng ấn ký âm khí quỷ dị trong cơ thể hắn, nghi Bạch Vi có điều khó nói hoặc bị cấm chế nên chỉ dám ám chỉ. Khi hắn đang trầm tư, Nhất Trần Tử tới cửa mời hắn dùng thực quả, rượu ngon và cùng bốn người luận đạo trước khi trời tối."},{"chuong":906,"tieuDe":"Linh Nhi","tomTat":"Vương Lâm được Nhất Trần Tử mời tới đình hóng mát phía bắc đại viện, nơi Trần Đạo Tam Tử đã chuẩn bị tiếp đãi để hóa giải hiềm khích trước đó. Trong đình, Linh Nhi được giới thiệu là vãn bối trong tộc Nhất Trần Tử, có tu vi Nguyên Anh và trời sinh Thủy Linh thể nên luôn phải được che chở để tránh bị kẻ xấu biến thành lô đỉnh. Thể chất và thanh âm của nàng khiến Vương Lâm nhớ tới cố nhân, vì vậy hắn tặng nàng mũ rơm có thể che giấu khí tức cùng ba cái chuông. Nhất Trần Tử nhận ra mũ rơm chứa cấm chế tinh diệu, hổ thẹn vì nhận hậu lễ cho hậu nhân nên lấy Thiên Minh Thạch đáp tặng Vương Lâm. Sau đó ông giới thiệu hai người còn lại là Liễu Nguyệt Long, đạo hiệu Nhất Long Tử, và Trận Tinh Hàn, đạo hiệu Nhất Tinh Tử. Khi được hỏi đạo hiệu, Vương Lâm nói mình là Ma Đạo Tử, khiến ba người cảm nhận sát khí giết chóc bốc lên. Đêm xuống, bốn người uống rượu và luận đạo, Nhất Trần Tử cho rằng đạo cần đoạn tuyệt phàm tục, còn Vương Lâm phản biện rằng người tu đạo không cần lẩn tránh tâm linh hay chữ thân."},{"chuong":907,"tieuDe":"Hiểu Ra Chân Tướng","tomTat":"Trong cuộc rượu cùng Trần Đạo Tam Tử, Vương Lâm nghe Nhất Long Tử nói về La Thiên Tinh Vực tiến công phía bắc và khiến Tu Chân Liên Minh bại lui. Khi Thiên Vận Tinh đột ngột nổi mưa sấm, lời nhận xét về thời tiết thất thường khiến hắn nhớ lại những câu nói trước đây của Bạch Vi. Vương Lâm lập tức hiểu ra Bạch Vi dùng chuyện thời tiết, Bạch Dương Mộc, Song Dục Tiên Quyết và âm khí trong cơ thể để ám chỉ Thiên Vận Tử cùng tình trạng nguy hiểm của mình. Hắn cáo từ Trần Đạo Tam Tử, thu Hứa Lập Quốc vào túi trữ vật rồi tới phòng Bạch Vi, phát hiện cấm chế phản chấn thần thức và căn phòng đã trống không. Nhận thấy việc Bạch Vi biến mất không đơn giản, Vương Lâm thi triển Hoán Vũ, đình chỉ mưa trong phạm vi mấy vạn dặm và dung thần thức vào từng giọt mưa để dò xét. Nhờ đó hắn tìm ra một thung lũng ẩn phía tây Quỷ Nhãn thành, nơi Bạch Vi xuất hiện với giọng nam hùng hậu, thần thái kiên định và không còn vẻ âm nhu trước đây."},{"chuong":908,"tieuDe":"Làm Thiên Vận Tử Sai Lầm Một Lần","tomTat":"Bạch Nguy tự xưng tên thật và khiến Vương Lâm nhận ra tình trạng âm khí trong cơ thể hắn đã dị thường tới mức tu sĩ bình thường không thể tồn tại. Hắn kể mình sinh trên Thiên Vận Tinh vào ngày cực dương hiếm thấy, còn muội muội song sinh mất thân thể nhưng linh hồn hấp thụ cực âm rồi dung nhập vào hắn. Sau khi vào Thiên Vận Tông và trở thành đệ tử Tử hệ, Bạch Nguy từng cầu Thiên Vận Tử tách linh hồn muội muội, nhưng Triệu Tinh Sát đột nhiên đánh thương hắn khiến hai linh hồn thức tỉnh và dung hợp. Thiên Vận Tử truyền Âm Dương Song Dục quyết với lời hứa tu tới tầng chín sẽ tách hồn, song Bạch Nguy dần phát hiện công pháp chỉ khiến kinh mạch dị biến, âm khí tăng mạnh và bản thân trở thành thực nghiệm để luyện ra tia chí dương. Bạch Nguy quyết định trước khi chết sẽ tặng tia chí dương mà Thiên Vận Tử cực kỳ mong muốn cho Vương Lâm, buộc hắn lựa chọn giữa nguy cơ kích phát sát tâm Thiên Vận Tử và bóng ma đạo tâm nếu lùi bước. Vương Lâm tự nhận mình là nghịch tu, đáp ứng nhận thử thách để khiến Thiên Vận Tử sai lầm một lần. Cuối chương, một nam tử áo bào tím bay tới tinh không Thiên Vận Tinh, gọi Vương Lâm là Tiểu Lâm tử và nhắc tới các nữ nhân lợi hại ở Phượng Loan tinh."},{"chuong":909,"tieuDe":"Nhất Chỉ Soán Thiên Vận","tomTat":"Trong thung lũng gần Quỷ Nhãn thành, Bạch Nguy nhắm mắt khi giờ Mão sắp qua, để âm khí trong cơ thể bùng phát dữ dội, đóng băng cỏ cây và phá vỡ cấm chế ngoài sơn cốc. Âm khí khiến mưa bên ngoài hóa thành tuyết, còn ấn ký nơi mi tâm hắn hút sạch lực lượng trong người. Bạch Nguy gào lên rằng muốn dùng cái chết của mình đổi lấy một lần tính toán sai lầm của Thiên Vận Tử, rồi thân thể mất sức sống, hóa thành tượng băng, để lại một điểm sáng vàng chứa tia cực dương. Vương Lâm bị âm khí đẩy lui dù có thân thể Cổ Thần, sau đó nhận ra điểm cực dương và đưa tay chụp lấy, khiến băng tuyết tan dần, cỏ xanh và mưa trở lại như cũ. Cùng lúc giờ Thìn tới, Thiên Vận Tử mở mắt tại Thiên Vận Tông, tự nói về đạo niệm muốn vận của mình trở thành vận của trời. Hắn nhìn về Quỷ Nhãn thành, gọi Vương Lâm to gan, rồi chỉ một ngón khiến nguyên lực thiên địa ngoài Thiên Vận Tinh tụ thành ngón tay khổng lồ. Chương kết bằng việc xác nhận đây không phải Cổ Thần Nhất Chỉ mà là đại thần thông do Thiên Vận Tử tự sáng tạo: Nhất Chỉ Soán Thiên Vận."},{"chuong":910,"tieuDe":"Tiến Tới","tomTat":"Thiên Vận Tử, với thân phận thành viên liên minh trưởng lão đoàn và uy danh khiến cả cường giả cùng cấp phải kiêng kỵ, thi triển một thần thông từ ngoài Thiên Vận Tinh. Thần thông hóa thành ngón tay khổng lồ mang thiên địa nguyên lực và ánh sáng bảy màu, ấn xuống khiến tầng không sụp đổ và nhắm thẳng thung lũng cách Quỷ Nhãn thành vài ngàn dặm. Dư uy của một chỉ lan tới Quỷ Nhãn thành, cuốn tan mây mưa sấm chớp và làm tường thành sụp đổ trong tiếng kinh hô. Vương Lâm đứng trong thung lũng, nhận ra khí tức Thiên Vận Tử, thu một tia cực dương vào túi trữ vật sau khi Thiên Nghịch hơi run, rồi lấy hoán vũ chi tinh do Thanh Thủy tặng ra để bảo mệnh. Cảnh chuyển tới Đại La tu chân tinh, nơi Đại La Kiếm Tông của Lăng Thiên Hậu có 990 thông thiên các hợp thành đại trận và một tháp lớn chứa bốn thanh nguyên thần kiếm. Lăng Thiên Hậu quan sát biến cố, nhắc Vương Lâm nằm trong danh sách Chu Tước, và quyết định nếu Vương Lâm chịu nổi thần thông mà không chết thì sẽ ra tay giúp hắn để khiến Thiên Vận Tử gặp phiền toái."},{"chuong":911,"tieuDe":"Phá Chỉ","tomTat":"Một chỉ thần thông của Thiên Vận Tử từ trời giáng xuống, ép thung lũng nơi Vương Lâm đứng nứt vỡ rồi bị nghiền thành hoang địa. Quỷ Nhãn thành ở gần chiến trường bị uy áp vạ lây, bảy tu sĩ gồm Trần Đạo Tam Tử phải kích hoạt quang trụ nâng cả thành bay về phương nam để tránh tai họa. Nhất Trần Tử và thành chủ Quỷ Nhãn thành không cứu viện nhưng vì không muốn bỏ lỡ trận giao phong giữa Tịnh Niết và Toái Niết nên quay lại quan sát. Vương Lâm phát động Hoán Vũ Chi Tinh, khiến hư ảnh Thanh Thủy hiện ra, hóa tinh thể thành mưa rồi thành giọt mưa đỏ xuyên phá sóng gợn bảy màu và chui vào đầu ngón tay. Khi nhận ra Thiên Vận Tử không hỏi về một tia cực dương có ẩn tình, Vương Lâm vẫn giữ chiến ý, lấy tiên giới toái phiến của Viêm Lôi Tử phóng đại thành đại lục chắn một chỉ. Nhân lúc hồng quang từ Hoán Vũ phá hoại đầu ngón tay từ bên trong, hắn dung nhập vào đại lục tiên giới, xông lên và tung một quyền vào đầu ngón tay khổng lồ."},{"chuong":912,"tieuDe":"Bế Tắc","tomTat":"Vương Lâm dồn nguyên lực dung hợp lực lượng Cổ Thần vào một quyền đã chuẩn bị từ lâu, đánh thẳng vào ngón tay khổng lồ do Thiên Vận Tử thi triển. Sau phản chấn, hắn tiếp tục lao lên đánh thêm nhiều quyền, cuối cùng khiến đầu ngón tay sụp đổ thành thiên địa nguyên lực. Thiên Vận Tử nhận ra Vương Lâm có pháp bảo liền phóng Phong Long bảy màu mang linh hồn rồng thật để truy kích. Trong lúc đối diện Phong Long, Vương Lâm suy xét về tia cực dương, Bạch Nguy và bố cục của Thiên Vận Tử, nhận ra lấy hay bỏ đều khiến đạo tâm rơi vào bế cục. Hắn kết luận chỉ có khiến Thiên Vận Tử tính sai một lần mới phá được thế, rồi định lấy vương miện từng thu Hoàng bào Chân Long để khắc chế Long Linh. Đúng lúc đó, Lăng Thiên Hậu cưỡi Kỳ Lân đỏ thẫm xuất hiện giữa biển lửa, để Kỳ Lân giao chiến với Phong Long và tạm thời giải nguy cho Vương Lâm. Vương Lâm cố ý nhắc chuyện bị sư tôn dùng thần thông muốn chém mình, còn Thiên Vận Tử cảnh cáo Lăng Thiên Hậu không được can thiệp chuyện Thiên Vận Tông. Lăng Thiên Hậu đáp trả gay gắt, tuyên bố nếu Thiên Vận Tử muốn chiến thì cứ chiến."},{"chuong":913,"tieuDe":"Thiên Vận Tử Áo Xám","tomTat":"Vương Lâm nghe cuộc đối đáp giữa Lăng Thiên Hậu và Thiên Vận Tử, nhận ra tu vi hai bên chênh lệch rất lớn nhưng quan hệ đối nghịch kéo dài mấy vạn năm vẫn ẩn chứa bí mật. Khi trời đất tối sầm, Thiên Vận Tử áo xám hiện thân và được Vương Lâm nhận ra là phân thân từng truyền Sát Lục Tiên Quyết cho mình. Ông ta hấp thu lực lượng ánh sáng, ngưng tụ hắc ám thành kiếm nhỏ màu đen rồi phóng ra mười đạo Sát Lục khí chân chính. Nhìn thấy điều này, Vương Lâm hiểu rằng nếu năm xưa không nhờ biến số Cổ Yêu và Tán Ma, hắn có thể đã bị luyện hóa thành một đạo Sát Lục khí trong tay Thiên Vận Tử. Lăng Thiên Hậu thi triển Phá Thiên thức thứ hai, khiến bốn kiếm nguyên thần dung hợp thành kiếm đồng mang Vũ Tiên Kiếm hình rắn. Vũ Tiên Kiếm hóa thành rắn lớn nghìn trượng lao tới, nhưng mười đạo Sát Lục khí lại biến thành mười bóng người, mỗi người phóng ra lượng Sát Lục khí khổng lồ khiến chiến trường bị sát khí bao phủ."},{"chuong":914,"tieuDe":"Nghịch Âm Dương","tomTat":"Trong lúc bị nhiều luồng khí Sát Lục truy kích trên Thiên Vận Tinh, Vương Lâm dùng mảnh vỡ Tiên Giới xoay quanh thân để phòng hộ và nhận ra Thiên Vận Tử áo xám vẫn chưa dùng toàn lực. Hắn nhớ lại phản ứng của Hạt châu Thiên Nghịch khi hấp thu tia cực dương, từ dấu Nhật Nguyệt sau Ngũ Hành viên mãn suy ra Thiên Nghịch hiện cần Âm Dương, và xem đây là điểm có thể phá bố cục của đối phương. Lăng Thiên Hậu ra tay đối kháng Thiên Vận Tử áo xám vì muốn phá việc của Thiên Vận Tử, thi triển Phá Thiên thức thứ ba để kiếm đồng tế linh vào Vũ Kiếm hình rắn. Thiên Vận Tử áo xám gom khí Sát Lục thành thanh kiếm đỏ thẫm, lấy kiếm đối kiếm với Lăng Thiên Hậu. Trước áp lực đó, Lăng Thiên Hậu tuyên bố cả đời chỉ tu Kiếm Đạo, lấy nguyên thần tu Kiếm Thần và máu thịt tế Kiếm Tôn, khiến nguyên thần hóa thành hư ảnh kiếm và làm kiếm trên Thiên Vận Tinh cùng chấn động. Thiên Vận Tử áo xám lần đầu biến sắc, thừa nhận kiếm đạo của Lăng Thiên Hậu đạt mức khiến hắn phải dùng bảy phần lực lượng. Hai kiếm va chạm, tạo gió xoáy bảy màu cuốn Vương Lâm, Lăng Thiên Hậu và Thiên Vận Tử áo xám rời Thiên Vận Tinh ra tinh không."},{"chuong":915,"tieuDe":"Côn Hư Thánh Nữ","tomTat":"Trong tinh không gần Thiên Vận Tinh, kiếm Sát Lục và Tiên Kiếm hình rắn giao kích dữ dội khiến cả hai cùng tổn hại: kiếm Sát Lục tan thành khí Sát Lục còn Tiên Kiếm hình rắn nứt thân. Thiên Vận tử áo xám cười dài rời về Thiên Vận Tinh, trong khi Thiên Vận tử bảy màu hiện thân đối chất với Lăng Thiên Hậu về việc can dự vào chuyện Thiên Vận Tông. Lăng Thiên Hậu lập tức mời Vương Lâm làm trưởng lão Đại La Kiếm Tông, tạo lý do hợp lệ để nhúng tay, nhưng Thiên Vận tử bảy màu lại bất ngờ nói bỏ qua “bên kia” rồi biến mất. Sau đó Lăng Thiên Hậu bói bằng năm mai rùa nhưng không thấy rõ lành dữ, đồng thời giải thích rằng danh sách Chu Tước khiến Thiên Vận tử khó dễ dàng giết Vương Lâm. Ông kể Chu Tước Thánh Hoàng từng có ân dẫn dắt mình, vì thế đề nghị xưng hô ngang hàng với Vương Lâm. Trên đường tới Đại La tinh, hai người bàn tiên thuật đạo pháp; Lăng Thiên Hậu thầm tán thưởng kiến thức của Vương Lâm, còn Vương Lâm nghi mục tiêu thật của Thiên Vận tử có thể là Lăng Thiên Hậu. Trước Đại La tinh, Lăng Thiên Hậu tiết lộ tinh cầu này vốn là mảnh vỡ hư tinh từ Côn Hư, được Hư Linh thượng nhân luyện hóa như kiếm và là phần thưởng từ nhiệm vụ của tu chân tông Côn Hư. Cuối chương, ông giải thích Côn Hư là nước tu chân cấp chín duy nhất trong Liên minh Tinh vực, nhắc khả năng nữ đệ tử áo phấn liên quan Côn Hư Thánh Nữ, rồi khiến Vương Lâm chấn động khi nói Tứ Thánh Tông từng là bá chủ Côn Hư."},{"chuong":916,"tieuDe":"Kinh Hồn","tomTat":"Vương Lâm theo Lăng Thiên Hậu tiến vào Đại La tinh và nhận ra quy mô của Đại La Kiếm Tông cùng Tứ Thánh Tông vượt xa tưởng tượng, với kiếm khí dày đặc, biển cả mênh mông, vô số tháp cao và mấy vạn đệ tử nghênh đón tông chủ. Lăng Thiên Hậu trước mặt toàn tông tuyên bố Vương Lâm là trưởng lão Đại La Kiếm Tông, rồi vào tháp bế quan, khiến Vương Lâm tạm có thân phận che chở trên Đại La tinh. Vương Lâm dùng thần thức Khuy Niết sơ kỳ trấn nhiếp đệ tử, hỏi Chu Tú về nơi ở, tự chọn một tòa tháp ngoài ngàn dặm, bố trí Đại Phiến Cấm và quyết định chủ động nuốt tia cực dương để phá tính toán của Thiên Vận tử. Tia cực dương vừa nhập mi tâm liền hóa biển lửa thiêu đốt thân thể Cổ Thần và nguyên thần, đẩy Vương Lâm tới sát ranh giới bị đốt thành tro. Đúng lúc nguy cấp, hạt châu Thiên Nghịch hiện ra trong nguyên thần, hút trọn biển lửa cực dương và làm dấu ấn Nhật trên hạt châu lóe sáng, khiến Vương Lâm thoát khỏi đau đớn. Lăng Thiên Hậu âm thầm quan sát thì bị ánh sáng vô hình từ biến cố này làm trọng thương, hư ảnh kiếm ở mi tâm gần như sụp đổ và hắn hoảng sợ chạy xuống trung tâm Đại La tinh. Trên Thiên Vận Tinh, Thiên Vận tử vốn bình tĩnh đếm thời gian Vương Lâm phải phun cực dương ra, nhưng khi bàn tay hư vô xuất hiện thì đạo tâm chấn động, liên tiếp dùng mây bảy màu, Bắc Đẩu Thất Tinh lực và Thất Tinh toái tiên mà vẫn không cản nổi. Cuối cùng hắn thi triển Thiên Vận thuật, triệu la bàn hư ảo khổng lồ, dùng Phụng Thiên Thừa Vận và Thiên Vật Thuật mở sáu đạo phong ấn để tiếp tục suy diễn cách đối phó với vật mà chính hắn nhận định là không thể chống cự."},{"chuong":917,"tieuDe":"Thiên Nghịch Lại Mở Ra","tomTat":"Bên ngoài Thiên Vận tinh, Thiên Vận Tử dùng hư ảnh la bàn đen trắng bao phủ tinh cầu để suy tính cách đối phó bàn tay khổng lồ đang ép tới. Hắn không tính ra toàn bộ nguồn gốc của bàn tay, nhưng quyết định thả nhiều phân thân hư ảo cho nó hấp thu nguyên lực rồi triệu Thiên Vận Kích từ ba ngọn núi hình chĩa ba để phản kích. Bàn tay không tiêu tán như hắn dự liệu mà nghịch chuyển, bắt lấy Thiên Vận Kích, hút ánh bạc rồi chộp lấy Thiên Vận Tử, khiến hắn trọng thương và đạo tâm viên mãn xuất hiện vết rạn. Sau khi thu hồi pháp bảo, hắn trở về Thiên Vận Tông sau núi bế quan, nhớ lại lần tính sai ở đoàn trưởng lão Liên minh năm xưa và tự nhận lần này mình lại sai vì Vương Lâm cùng bàn tay hư ảo. Cùng lúc đó, Lăng Thiên Hậu bị ánh sáng vô hình truy đuổi vào sâu trong Đại La tinh, nơi các phong ấn và trận pháp đều không ngăn nổi nó. Hắn hy vọng dựa vào tế hỏa do Hư Linh Thượng Nhân để lại, nhưng ánh sáng vẫn hóa thành bàn tay khổng lồ chộp tới, khiến hắn kinh hãi vì chỉ dùng thần thức dò xét Vương Lâm mà bị dây dưa không dứt."},{"chuong":918,"tieuDe":"Thiên Nghịch Lại Mở Ra","tomTat":"Lăng Thiên Hậu tăng tốc chạy tới nơi có tế hỏa và nhìn thấy Hỏa chu tước màu đen, nhưng bị bàn tay hư ảo phía sau cách không nắm lấy. Máu thịt, nguyên lực, nguyên thần và linh hồn của hắn bị hút đi dữ dội, tới lúc tuyệt vọng thì hắc mang trên mi tâm lóe lên khiến bàn tay buông ra. Sau biến cố này, Lăng Thiên Hậu bị trọng thương nặng, chọn bế quan khôi phục và từ bỏ ý định tìm Vương Lâm báo thù. Ở Đại La Kiếm Tông, Vương Lâm cảm nhận hạt châu Thiên Nghịch phóng ra hai đạo hào quang rồi thu hồi, khiến đồ án mặt trời trên hạt châu chuyển động. Trong mười ngày kế tiếp, hào quang từ Thiên Nghịch làm nguyên lực của hắn sinh cực nóng, nguyên thần Thái Cổ Lôi Long xuất hiện khối khí đỏ và thân thể Cổ Thần được tăng cường. Ngày thứ mười một, con mắt thứ ba tự mở, lực bổn nguyên từ Chiến tự thiếp và cảm ngộ ở phù tộc dung nhập Thiên Nghịch như chìa khóa, đưa thần thức hắn vào không gian có cánh cửa lớn. Trước khe cửa Thiên Nghịch, Vương Lâm suýt mê lạc nhưng được cực dương giúp tỉnh lại, từ đó nhận ra Ngũ Hành viên mãn chỉ khiến cửa hiện ra còn cực dương là một nửa Âm Dương giúp hắn giữ tỉnh táo. Hắn quyết đoán bước vào khe cửa để tìm bí mật chân chính của Thiên Nghịch."},{"chuong":919,"tieuDe":"Đường Hẹp","tomTat":"Khi Vương Lâm sắp bước qua cánh cửa Thiên Nghịch, tâm thần hắn bị kéo ngược qua tháng năm, trở lại trạng thái thai nhi rồi vượt qua một tầng ngăn cản kỳ dị. Hắn nhìn thấy đời sống ngắn ngủi của một con chim, chứng kiến nó chết trong miệng mãng xà và chấn động trước nhận thức về bổn nguyên, nhưng sau đó gặp tầng ngăn cản mạnh hơn, chỉ kịp thấy hồng quang rồi bị đẩy bật trở lại. Tỉnh lại trước cánh cửa đang khép, Vương Lâm đứng dậy trong Đại La Kiếm Tông, khí tức bộc phát đạt đỉnh Khuy Niết trung kỳ, khiến nguyên lực toàn Đại La tinh hóa thành lốc xoáy và đệ tử trong tông chịu uy áp nặng nề. Hắn suy luận hình ảnh con chim không hẳn là đời trước mà là biểu tượng tâm thần, đồng thời cho rằng phải chờ Thiên Nghịch đạt Âm Dương đại viên mãn mới có đáp án. Từ dấu vết tòa tháp và thời điểm Lăng Thiên Hậu bỏ chạy, Vương Lâm kết luận bố cục của Thiên Vận tử đối với mình hoặc Lăng Thiên Hậu đã bị phá, rồi rời Đại La tinh để chuẩn bị trở về vùng đất Yêu Linh. Trên đường, hắn tới một tinh cầu hoang dã hình trăng lưỡi liềm, nơi Đồng tử đầu to và Lôi Cát đã chờ sẵn theo an bài trước đó và cùng bái kiến hắn."},{"chuong":920,"tieuDe":"Phù Phong Tử","tomTat":"Vương Lâm nhận thấy tinh cầu bỏ hoang hiện tại quá ác liệt, không thích hợp để Đầu to và Lôi Cát bế quan, nên dẫn hai người rời đi tìm tinh cầu tu chân khác. Trong tinh không, Lôi Cát hóa thân Cự Ma Tộc cao trăm trượng làm vật cưỡi, Vương Lâm ngồi trên lưng hắn, còn Đầu to và Tháp Sơn đứng cạnh như hộ vệ, khiến tu sĩ dọc đường kính sợ và tự nhường đường. Trên đường, Vương Lâm cảm nhận tu vi đã đạt đỉnh Khuy Niết trung kỳ, tự đánh giá mình có thể không ngại Tịnh Niết sơ kỳ và đủ tư cách liều mạng với Tịnh Niết trung kỳ. Một con thuyền đen chở lão già núi thịt cùng các cô gái, bảy hộ vệ áo đen và hơn trăm tu sĩ áo xanh xuất hiện, hai bên nhận ra nhau vì từng gặp ở Thiên Vận tinh. Bảy hộ vệ áo đen uy hiếp nhóm Vương Lâm phải nhường đường, khiến Đầu to xin phép khai sát và lao vào giao chiến với chúng. Nhóm hộ vệ bày trận hợp lực hóa ra hổ đen, còn lão già núi thịt phóng hắc mang can thiệp, nhưng Vương Lâm thuấn di tới đánh tan đòn này. Vương Lâm trực tiếp hỏi lão già có dám đánh một trận hay không, còn lão già xem nhẹ hắn vì cho rằng hắn từng đấu Lăng Thiên Hậu nhờ pháp bảo. Cuối chương, lão già thi triển Tiên Bi Diệt Thần, gọi hư ảnh bia đá kim quang đè xuống Vương Lâm, mở màn trận thử sức mới."},{"chuong":921,"tieuDe":"Phù Phong Tử (P2)","tomTat":"Vương Lâm bình tĩnh nghênh chiến Trần Phong, dùng một quyền dung hợp tu vi Khuy Niết trung kỳ đỉnh phong và lực lượng Cổ Thần phá bia đá cùng chín dấu ấn của đối phương. Trong lúc trận chính diễn ra, Đại Đầu lao vào bảy người áo đen và tàn sát toàn bộ nhóm tùy tùng trực tiếp của Trần Phong. Trần Phong vì tham chìa khóa Tiên Phủ và vật cưỡi Cự Ma Tộc nên dốc sức thi triển Đồ La Phù trần, nhưng bị Vương Lâm dùng Diệt Thần Mâu phá tan. Khi Trần Phong dùng thanh quang thuẫn chặn đòn rồi Huyết độn bỏ chạy, Vương Lâm lần đầu thi triển Súc địa thành thốn trong phạm vi Thiên Vận tinh, áp sát đến mức đối phương không còn đường thoát. Trần Phong xin tha, dâng thanh quang thuẫn, nhận nô ấn và tự khai tên thật Trần Phong, đạo hiệu Phù Phong tử, hứa trợ lực trong chuyến vào vùng đất Yêu Linh. Sau đó nhóm Vương Lâm tới gần Thủy Linh tinh của Trần Đạo Tam Tử; Nhất Trần tử cùng hai người còn lại bay ra vì cảm nhận khí tức tu sĩ bước thứ hai. Trần Đạo Tam Tử kinh hãi khi thấy Lôi Cát, Vương Lâm và Phù Phong tử, rồi càng chấn động khi Vương Lâm nói thẳng Phù Phong tử là người hầu của mình. Nhất Trần tử vì muốn kết giao nên chủ động mời Vương Lâm ở lại Thủy Linh tinh tu luyện."},{"chuong":922,"tieuDe":"Còn Nhớ Linh Nhi?","tomTat":"Vương Lâm do dự trước lời mời ở lại Thủy Linh Tinh, nhưng sau khi Nhất Trần Tử cùng Nhất Tinh Tử và Nhất Long Tử khuyên nhủ, hắn đồng ý tạm cư tại đây để tu luyện. Nhất Trần Tử dẫn đường, Lôi Cát thu nhỏ thân hình, Đầu To, Tháp Sơn và Phù Phong Tử theo sau Vương Lâm, cả đoàn vượt tầng cương phong tiến vào tinh cầu. Trên đường, Triệu Tuyết và Linh nhi cưỡi tiên hạc xuất hiện; Triệu Tuyết hành lễ với sư phụ, sư thúc và Vương Lâm, còn Linh nhi hỏi Vương Lâm có còn nhớ mình không. Vương Lâm nhắc lại chiếc mũ và chuông từng tặng khiến Linh nhi đỏ mặt, đồng thời làm Triệu Tuyết thêm tò mò về vị Vương tiền bối mà Linh nhi thường nhắc đến. Nhất Trần Tử đưa Vương Lâm tới quần thể cung điện phía Đông Thủy Linh Tinh, nơi linh khí dày đặc nhất, rồi Trần Đạo Tam Tử cáo từ. Vương Lâm ra lệnh bế quan, để Tháp Sơn hộ pháp và yêu cầu Lôi Cát, Đầu To, Phù Phong Tử chọn chỗ ở trong phạm vi trăm dặm. Sau ba ngày tĩnh tọa, hắn củng cố vững chắc Khuy Niết trung kỳ, tự đánh giá chiến lực của mình khi phối hợp thân thể Cổ Thần vẫn chưa đủ đối phó Tiên phủ ở Yêu Linh chi địa. Cuối cùng, hắn lấy thanh quang tiểu thuẫn do Phù Phong Tử từng giao ra nghiên cứu, phát hiện trong đó có khí tức Cổ Thần bị che đậy và nghi pháp bảo này do một Cổ Thần khác ngoài Đồ Ti thời thái cổ tế luyện."},{"chuong":923,"tieuDe":"Thanh Quang Thuẫn","tomTat":"Vương Lâm kiểm tra Thanh quang tiểu thuẫn trong cung điện và phát hiện ấn ký Thanh Long đang giam khí tức Cổ Thần bên trong. Khi hắn phá ấn, ấn ký hóa thành thanh long tấn công, lại phân ra thanh khí nhằm vào mi tâm, nhưng bị con mắt thứ ba của hắn hút vào trước khi bản thể bị bóp tan thành mảnh vỡ khắc thanh long. Từ khí tức trên mảnh vỡ, Vương Lâm liên hệ tới ấn ký Chu Tước và Thanh Long Thánh Tông, rồi tiếp tục dùng vương tộc Cổ Thần lực tách thần niệm ẩn trong khí xoáy của thuẫn. Thần niệm tự xưng là Thanh Long Thánh Hoàng, nói mình gặp nạn tại Vũ chi tiên giới và hứa trọng thưởng cho người cứu hoặc truyền tin. Sau khi thần niệm tan đi, khí tức Cổ Thần bị áp chế trong thuẫn bùng nổ, buộc Vương Lâm đưa thuẫn ra giữa không trung, nơi nó phóng đại thành pháp khí khổng lồ kèm hư ảnh Cổ Thần bao phủ Thủy Linh tinh. Trần Đạo Tam Tử, Linh nhi, nhóm Đại Đầu, Lôi Cát và Phù Phong tử đều bị dị tượng chấn động; Lôi Cát nhớ tới thánh tổ vật Cự Ma tinh, còn Phù Phong tử càng kiêng kị Vương Lâm vì bản thân từng không phá được bí mật của thuẫn. Cuối chương, Thanh quang thuẫn gần ba trăm trượng dừng bành trướng, hư ảnh Cổ Thần cúi đầu và tinh điểm mi tâm ngừng lại, khiến Vương Lâm vừa mừng như điên vừa khiếp sợ."},{"chuong":924,"tieuDe":"Thần Thông Bảo Mệnh Của Cổ Thần","tomTat":"Vương Lâm nhìn thấy trên Thanh quang thuẫn hiện ra hư ảnh một Cổ Thần xa lạ có tám tinh điểm và tinh điểm thứ chín mơ hồ, nhận ra chủ nhân cũ của tấm thuẫn từng gần đạt Cửu tinh Cổ Thần. Hắn đặt tay lên tấm thuẫn, để Cổ Thần lực bạo ngược tràn qua thân thể mình, rồi tiếp nhận tin tức truyền thừa và dùng ngôn ngữ Cổ Thần hô âm “Thê” khiến tấm thuẫn khổng lồ thu nhỏ lại. Vương Lâm so sánh tấm thuẫn với Cổ Thần Đỉnh của Đồ Ti, nhận định đây là pháp bảo từng được Cổ Thần xa lạ thật sự sử dụng chứ không phải vật tùy tay vứt bỏ. Để thử uy lực, hắn yêu cầu Phù Phong Tử thi triển toàn lực; thần thông bia đá tử quang bị Thanh quang thuẫn tự động phá nát, thiên địa nguyên lực bên trong cũng bị hút sạch. Từ tin tức nhận được, Vương Lâm biết tấm thuẫn có thể tích đủ sức mạnh trời đất để mở ra thần thông bảo mệnh do Cổ Thần xa lạ phong ấn, nên thu nó vào đồng tử mắt phải. Cuối chương, Tư Đồ Nam xuất hiện bên ngoài Thiên Vận Tinh cùng một nữ tử phong tao quyến rũ, nói mình đến tìm huynh đệ nhiều năm không gặp và nhớ tới Vương Lâm sau mấy trăm năm xa cách."},{"chuong":925,"tieuDe":"Mộng Như Luân Hồi","tomTat":"Tư Đồ Nam ôm nữ tử Phấn Hồng Cung bay về hướng Thiên Vận Tinh, vừa trêu ghẹo vừa nghĩ tới cảnh xưng bá Phượng Loan Tinh và hưởng lạc cùng Vương Lâm. Sau biến cố tại Thủy Linh Tinh, Vương Lâm trở lại cung điện bế quan, còn nhiều người như Trần Đạo Tam Tử, Phù Phong tử và Linh nhi đều không thể tĩnh tâm. Linh nhi bị bóng dáng Cổ Thần ngoài đời làm chấn động, trong mộng lại thấy mình đứng trên tế đàn trong mây, chứng kiến đám người kỳ dị tụng niệm và Cổ Thần tám tinh hiện thân. Nàng nhận ra giấc mộng này đã theo mình từ nhỏ nhưng sau khi gặp Vương Lâm mới trở nên rõ ràng, khiến nàng nghi ngờ nó không chỉ là ảo tưởng. Sáng sớm, Triệu Tuyết tới tìm nhưng không thấy Linh nhi trong phòng. Trong cung điện, Vương Lâm suy tính thần thông bảo mệnh Cổ Thần cần sức mạnh thiên địa khổng lồ, rồi kiểm tra vương miện có hồng ảnh nghi liên quan Hồng Điệp nhưng không nhận được đáp lại. Hắn tiếp tục lấy nữ luyện thi áo bạc của Hài Ngục Giới ra, định tế luyện làm trợ lực cho chuyến tới Yêu Linh chi địa. Khi Linh nhi đến ngoài cung điện cầu kiến, Vương Lâm thu luyện thi và tán âm khí, còn Tháp Sơn lạnh lùng canh giữ, sẵn sàng ra tay nếu nàng tiến thêm."},{"chuong":926,"tieuDe":"Bảo Bình","tomTat":"Linh nhi đến trước cung điện của Vương Lâm từ sáng sớm, ngượng ngùng mời hắn cùng ngắm bình minh Thủy Linh Tinh, nhưng Vương Lâm giữ khoảng cách trưởng bối và từ chối, bảo Tháp Sơn hộ tống nàng thay mình. Khi nàng sốt ruột muốn hỏi về hư ảnh người khổng lồ đêm trước, Tháp Sơn tỏa gợn sóng đẩy lùi khiến linh lực nàng tán loạn đến phun máu, buộc Vương Lâm xuất hiện truyền nguyên lực chữa thương rồi miễn cưỡng đồng ý đi cùng nàng một lần. Linh nhi gọi tiên hạc bằng tiếng chuông cổ tay, dẫn hắn tới một tuyệt phong nhìn ra biển; trước cảnh mặt trời mọc, Vương Lâm lần đầu rơi vào một trạng thái cảm ngộ kỳ dị ngắn ngủi khó quên. Sau đó Linh nhi phủ nhận lời hắn nói hư ảnh chỉ là linh khí pháp bảo, tiết lộ nàng nhiều lần lạc vào cảnh mộng thấy những người khổng lồ trên trời có tinh điểm ở mi tâm. Vương Lâm chấn động vì ký ức Đồ Ti không có manh mối giải thích việc phàm nhân thấy Cổ Thần trong mộng, cho rằng chuyện quá hoang đường và muốn nàng rời đi. Không do dự, Linh nhi quỳ xuống, hai tay đặt trước ngực thành dấu rồi giơ cao theo nghi thức từng thấy vô số lần trong mộng, khiến Vương Lâm hai mắt ngưng lại và đầu óc trống rỗng."},{"chuong":927,"tieuDe":"Thủy Cảnh","tomTat":"Mi tâm Vương Lâm tự hiện năm ngôi sao Cổ Thần, kích phát ký ức truyền thừa của Cổ thần Đồ Ti và khiến Linh nhi rung động linh hồn. Linh nhi mở ra ký ức ẩn sâu, tái hiện thân phận Thần nô Mộc Linh của Nguyệt tộc Thái cổ nửa quỳ trên tế đàn cầu Cổ Thần ban thần lực chinh chiến Tháp tộc. Trong ảo cảnh, dân chúng Nguyệt tộc dâng thiên địa lực qua bảo bình cho Cổ Thần hình dáng Vương Lâm, rồi thần lực phản hồi chia xuống dân chúng qua Thần nô. Ở hiện thực, Linh nhi ngã xuống hôn mê và mi tâm hiện dấu ấn liên kết với nhịp tim Vương Lâm. Vương Lâm hiểu ra cơ chế Thần nô, biết lạc ấn cũ của Linh nhi đã bị dấu ấn của hắn thay thế nên sinh tử nàng gắn với hắn. Hắn cũng ngờ truyền thừa ký ức Đồ Ti chưa trọn vẹn, còn phần bị phong ấn. Cuối cùng, trong lúc thổ nạp cảm nhận mặt trời mọc lặn, hắn vô tình chạm tới bên bờ Thủy Cảnh, một trong ba đại cảnh giới Cực, Đạo, Thủy của Tu Chân Giới."},{"chuong":928,"tieuDe":"Thần Thông Tàn Dạ","tomTat":"Chương mở đầu bằng thuyết về ba cảnh Cực, Đạo, Thủy cùng truyền thuyết luyện khí sĩ Thượng cổ Lưu Văn từng ghi chép Thần thủy, bế quan thành cường giả rồi mất tích thần bí, để lại lời đồn “Cực Cảnh là tử, Thủy Cảnh là sinh”. Vương Lâm chìm trong trạng thái cảm ngộ khó nắm bắt, thấy một tia rõ ràng trước mắt nhưng không chộp được, nên kiên nghị chờ qua từng lần mặt trời mọc lặn. Linh nhi tỉnh dậy trong đêm, ký ức phong ấn mở ra, tự xưng thần nô Mộc Linh bái kiến Cổ Thần rồi cưỡi tiên hạc rời đi theo lệnh hắn. Sau hơn hai tháng Vương Lâm ngồi bất động, quanh mười dặm sinh ra lực lượng vô hình đẩy lùi mọi người, khiến Trần Đạo Tam Tử, Đầu to, Tháp Sơn, Lôi Cát và Phù Phong tử đều tới quan sát. Trần Đạo Tam Tử phán đoán hắn có thể đang ngộ đạo và quyết yên lặng theo dõi. Phù Phong tử lại bí mật xem đây là cơ hội ngàn năm có một để phá dấu ấn nhưng còn do dự vì sợ biến cố. Đến ngày thứ chín sau hai tháng, hai mắt Vương Lâm đầy tia máu, quên hết xung quanh và tia rõ ràng trong cảm nhận ngày càng hiện rõ."},{"chuong":929,"tieuDe":"Tàn Dạ Chi Lực","tomTat":"Trên biển Thủy Linh tinh, mưa lớn và mây đen che kín bầu trời, Vương Lâm sau hơn hai tháng chờ đợi dồn toàn bộ tâm thần vào khoảnh khắc mặt trời mọc. Khi mặt trời vượt khỏi mặt biển, hắn bắt được một tia mạch lạc của lực lượng phá tan màn đêm, để nó dung nhập vào cơ thể và bước vào trạng thái cảm ngộ sâu. Phù Phong tử chọn đúng lúc này lao tới, tin rằng giết Vương Lâm thì các phong ấn trên người mình sẽ bị phá bỏ. Vừa tiến vào phạm vi mười dặm, hắn bị cuốn vào cảnh tượng mặt trời rực lửa xé nát đêm tối, thân thể và nguyên thần đều đau đớn như bị phá vỡ. Hắn liên tiếp dùng gió lốc thiên địa nguyên lực và thần thông Tịnh Niết ngưng thành quả cầu nguyên lực để chống lại, nhưng các thủ đoạn này đều bị ánh sáng và lực lượng tàn dạ nghiền nát. Trong cơn kinh hãi, Phù Phong tử nhận ra bóng người trong mặt trời chính là Vương Lâm, còn cảnh mặt biển dần hiện thành đỉnh núi cao. Cuối chương, hắn cố mở túi trữ vật để tiếp tục ứng biến, nhưng cánh tay phải lập tức nổ nát thành máu thịt."},{"chuong":930,"tieuDe":"Một Khắc Tối Cường","tomTat":"Phù Phong tử trong lúc bị lực kỳ dị xé rách thân thể liên tục lấy pháp bảo ra chống đỡ, nhưng các pháp bảo vừa xuất hiện đã vỡ nát. Hắn tiếp tục gọi ra tấm bia đá đen cùng con trăn lớn có sừng để công kích, còn Vương Lâm vẫn ngồi khoanh chân trên đỉnh núi và chỉ nâng tay thi triển Tàn Dạ. Ý cảnh mặt trời mọc từ biển xé tan màn đêm quét ngang, khiến con trăn bị xé nát, bia đá vỡ vụn và Phù Phong tử trọng thương ngã xuống đất. Trần Đạo Tam tử, Đồng tử đầu to, Lôi Cát và Tháp Sơn đều chứng kiến uy lực ấy, mỗi người có phản ứng riêng trước sự biến chất sức mạnh của Vương Lâm. Sau trận, Vương Lâm nắm tóc Phù Phong tử mang về cung điện, suy ngẫm trạng thái cảm ngộ vừa trải qua và so sánh nó với không gian kỳ dị của Cổ Yêu Bối La ở đất Yêu Linh. Trong cung điện, Phù Phong tử nhận ra Tàn Dạ là thần thông do Vương Lâm tự nghĩ ra, bị chấn nhiếp hoàn toàn và thề bằng đạo tâm sẽ không phản kháng lần nữa."},{"chuong":931,"tieuDe":"Cướp Người","tomTat":"Phù Phong tử nhắc Vương Lâm rằng vùng đất Yêu Linh trên Thiên Vận tinh sẽ mở lại trong vài tháng đến nửa năm, rồi trở về cung điện bế quan dưỡng thương. Vương Lâm kiểm chứng lực tàn đêm, phát hiện thần thông này tiêu hao nguyên lực cực mạnh khi dùng bình thường nhưng ở khoảnh khắc mặt trời mọc có thể mượn sức trời đất mà thi triển, nhờ đó trở thành thời điểm chiến lực mạnh nhất của hắn. Sau đó hắn phong kín cung điện bằng cấm chế, Tâm Cấm thuật và la bàn truyền nhân Phá Diệt Cấm để xử lý Ngân Y Luyện Thi. Nữ thi tỉnh lại phản kháng dữ dội bằng tiếng rít, sương đen, cây kéo đỏ và xiềng xích, nhưng bị Vương Lâm dùng ánh sáng xanh, đại đỉnh Cổ Thần, hoán vị và la bàn ép vào trung tâm trận cấm. Vương Lâm rút hai đoạn xích khỏi xương tỳ bà và xương chậu của nàng, bóp nát chúng rồi dùng thủ đoạn từ thuật Thi vệ trong ngọc giản Thanh Sương để luyện hóa, khiến nàng sau hơn nửa tháng mất oán hận và mi tâm hiện dấu ấn. Trên Thiên Vận tinh, Tư Đồ Nam trở thành cung chủ Hồng Phấn cung, dùng tu vi Tịnh Niết, đan dược và tiên thuật lôi kéo nhiều nữ tu, đồng thời dò hỏi tin tức Vương Lâm. Khi biết Triệu Tuyết và Linh nhi là hai nữ đệ tử của Trần Đạo Tam Tử trên Thủy Linh tinh, hắn dẫn hàng trăm nữ tu tới đó, ngoài mặt ham sắc nhưng thực chất định cướp người làm lễ gặp mặt cho Vương Lâm. Trong khi ấy Thiên Vận tông bị phong bế theo lệnh Thiên Vận tử trước khi bế quan, khiến Tư Đồ Nam khó thăm dò sâu hơn."},{"chuong":932,"tieuDe":"Gặp Lại","tomTat":"Tư Đồ Nam đứng ngoài Thủy Linh tinh, dùng thần thức Tịnh Niết sơ kỳ quét ngang tinh cầu khiến trời đất biến sắc, Trần Đạo Tam Tử bị ép hiện thân và nhiều tu sĩ trong tinh cầu bị thương. Lôi Cát phun máu nhưng không khuất phục, còn Đồng tử đầu to lập tức đến nơi Vương Lâm bế quan, cùng Tháp Sơn hộ pháp cho hắn. Vương Lâm lúc này đang ở khoảnh khắc quyết định khi tế luyện nữ thi, tâm thần gần như nối liền với nàng nên thần thức Tư Đồ Nam chỉ cảm nhận được nữ thi có tu vi Tịnh Niết sơ kỳ. Sau khi thu thần thức, Tư Đồ Nam công khai đòi giao cô bé có Thủy Linh căn và Triệu Tuyết, đồng thời khinh thường hai tu sĩ Tịnh Niết bị thương trong tinh cầu. Nhất Trần tử ra lệnh mở đại trận phòng hộ, cùng Nhất Tinh tử và Nhất Long tử dùng ba lệnh bài màu đen tạo ba tầng hào quang bao phủ Thủy Linh tinh. Tư Đồ Nam áp sát tinh cầu, tự nhận đang tìm lô đỉnh cho huynh đệ, rồi dùng Trai diệt phá tầng phòng hộ đầu tiên. Hắn tiếp tục thi triển Nhất Chỉ Thiên Địa, Tịch Thất Càn Khôn và Tịch Diệt biến, nén thiên địa nguyên lực thành lốc xoáy mạnh hơn, phá tiếp tầng thứ hai và chạm vào tầng phòng hộ cuối cùng."},{"chuong":933,"tieuDe":"Gặp Lại (P2)","tomTat":"Tư Đồ Nam mang lốc xoáy xông vào Thủy Linh tinh, phá tan ba tầng đại trận phòng hộ khiến Trần Đạo Tam Tử vì tâm thần liên kết với trận mà phun máu lùi lại. Hắn tự xưng trước Nhất Trần tử, bác bỏ lời thương lượng và tuyên bố đến tìm người cho người anh em, rồi khi Triệu Tuyết cùng Linh nhi xuất hiện thì nhận ra Linh nhi là Thủy Linh căn và cuốn cả hai đi. Nhất Trần tử đau đớn cầu Vương Lâm giúp đỡ, nhưng Vương Lâm đang ở thời khắc then chốt luyện thi nên chỉ có thể giữ thần thức quanh cung điện. Nghe hai chữ Vương huynh, Tư Đồ Nam lập tức chú ý người họ Vương trong cung điện và quyết định đến xem tận nơi. Phù Phong tử vì từng được Vương Lâm tha chết nên ra mặt chặn đường, nhưng bị Hoàng Tuyền Chỉ đã cải thiện của Tư Đồ Nam ép lui. Tháp Sơn và Đầu to tiếp tục ngăn cản cũng bị đánh bật, còn Tư Đồ Nam đến gần cung điện thì lộ vẻ cực kỳ cổ quái. Cấm chế trong cung điện lao ra muốn phong ấn hắn nhưng bị lốc xoáy phá tan phần lớn, sau đó nữ thi áo bạc xuất hiện, lao vào Tư Đồ Nam và dùng cây kéo phá quầng sáng Khốn Tiên chỉ."},{"chuong":934,"tieuDe":"Độc","tomTat":"Sau hiểu lầm ban đầu, Tư Đồ Nam tiến tới chỗ Vương Lâm và dùng Nhất Chỉ Sơn Động để thử sức, nhưng thần thông bị lực thân thể của Vương Lâm phá vỡ khiến hắn vừa kinh hãi vừa hưng phấn. Hắn tiếp tục thi triển bản đầy đủ Sơn Động Nhất Chỉ, ngưng tụ hồn tất cả núi trên Thủy Linh tinh, còn Vương Lâm dùng quyền Cổ Thần đối kháng khiến thiên địa chấn động và biển cả dậy sóng. Trận luận bàn kết thúc trong tiếng cười, hai người nhận ra tình huynh đệ từng trải qua sinh tử vẫn còn nguyên sau mấy trăm năm. Trần Đạo Tam Tử và Phù Phong tử chứng kiến biến chuyển này, hiểu rằng người anh em mà Tư Đồ Nam từng nhắc rất có thể chính là Vương Lâm, trong khi Phù Phong tử chú ý người con gái áo bạc vẫn còn sống giữa đống hoang tàn. Sau đó Vương Lâm đưa Tư Đồ Nam tới đỉnh núi từng cảm ngộ Tàn Dạ, hai người uống rượu và kể lại những trải nghiệm xa cách. Tư Đồ Nam nhắc tin tức về Thiên Vận tinh, Phượng Loan tinh, cuộc chiến La Thiên với Liên minh và nhận ra Chính Phẩm Lôi Tiên Hứa Mộc chính là Vương Lâm. Khi nhìn lại hành trình của bạn cũ từ thiếu niên Hằng Nhạc Phái, mất người thân, hóa phàm, cảm ngộ Luân Hồi đến tu vi hiện tại, Tư Đồ Nam thấy Vương Lâm tuy hiển lộ Khuy Niết trung kỳ nhưng ẩn chứa sức mạnh khiến cả hắn ở Tịnh Niết sơ kỳ cũng kinh hãi."},{"chuong":935,"tieuDe":"Say","tomTat":"Vương Lâm gặp lại Tư Đồ Nam trên Thủy Linh tinh, cùng uống rượu và nhớ lại ân tình năm xưa từ nước Triệu, Thiên Nghịch đến những thần thông mà Tư Đồ Nam từng truyền cho hắn. Tư Đồ Nam kể chuyện mình gây họa ở Phượng Loan tinh, bị nữ tu nơi đó truy sát và trúng Dục Tiên Dục Tử, một loại độc Tiên Giới dung hợp nguyên thần và có thể khiến hình thần câu diệt. Vương Lâm kiểm tra độc thương, nổi sát ý với Phượng Loan tinh nhưng quyết định việc giải độc cho Tư Đồ Nam quan trọng hơn báo thù, rồi nghĩ tới tiên tháp có xác Thanh Sương và khả năng Thanh Lâm trong động phủ vùng đất Yêu Linh có thể cứu nàng, từ đó phá độc. Tư Đồ Nam đồng ý cùng Vương Lâm vào vùng đất Yêu Linh, đồng thời trêu hắn về nữ nhân trên Thủy Linh tinh, khiến Vương Lâm nhớ tới Lý Mộ Uyển, Liễu Mi và Vương Bình. Trong men rượu, Vương Lâm bộc lộ nỗi đau hơn một ngàn ba trăm năm tu đạo, mất cha mẹ, người thân, người yêu, con và niềm vui bình thường, rồi tự hỏi mình rốt cuộc theo đuổi điều gì. Tư Đồ Nam lấy rượu tiên cho hắn tìm lại cảm giác say của người thường. Hai tháng sau, Thiên Vận Tử mở đại trận Thiên Vận tông trên Thiên Vận tinh, phát thiệp mời tới các lão quái đủ tư cách vào vùng đất Yêu Linh, thông báo mười ngày sau mở cửa động phủ Tiên nhân ở Đông Hải Triều tịch. Tin động phủ có thể liên quan tới Tiên Đế Thanh Lâm và bí mật bước tu đạo thứ ba khiến các lão quái đại thần thông chấn động."},{"chuong":936,"tieuDe":"Hồn","tomTat":"Thanh Lâm được nhắc là Tiên Đế chí tôn từng bước vào bước tu đạo thứ ba, không chết sau đại họa Tiên Giới nhưng bị thương nặng và có khả năng bế quan trong động phủ sâu vùng đất Yêu Linh. Thiên Vận tử phát thiệp mời, Lăng Thiên Hậu cũng gọi trợ thủ, khiến nhiều tu sĩ tụ về Thiên Vận tinh trước ngày vào Triều tịch dù chiến sự La Thiên và Liên minh khiến số đại thần thông giả thực sự tham dự bị hạn chế. Đến ngày thứ mười, Thiên Vận tử áo trắng đạp cây đinh ba đen tới cửa Triều tịch, sau đó lão già hồ lô, nhóm nữ tu trên mây tía, Tôn trưởng lão áo tím và Lăng Thiên Hậu lần lượt xuất hiện. Tôn trưởng lão mang hạc tím ba mắt, làm Thiên Vận tử nhíu mày và lão già hồ lô biến sắc, đồng thời báo với Lăng Thiên Hậu rằng một nhân vật khác cũng đã nhận lời mời. Bên dưới Triều tịch, bộ lạc Luyện Hồn trong vùng đất Yêu Linh đã bành trướng mạnh mẽ qua vài trăm năm, dung hợp nhiều bộ lạc và phát triển tới vài trăm vạn tộc nhân. Thập Tam nhờ điên cuồng sưu tập hồn phách mà có thực lực đối kháng Yêu Soái, còn Âu Dương Hoa có chín mươi chín cây cờ có thể gọi vài triệu hồn phách. Cuối chương, bộ lạc Luyện Hồn dốc toàn lực tiến vào quận Hỏa Yêu để đoạt quận, mang theo tượng đá đen khắc lão tổ mà toàn tộc sùng kính và tin rằng một ngày lão tổ sẽ trở về."},{"chuong":937,"tieuDe":"Đã Đến","tomTat":"Bên ngoài Thiên Vận tinh, khu vực Đông Hải Triều tịch đã tụ tập đông đảo tu sĩ và nhiều đại thần thông, tất cả dường như đang chờ một người cuối cùng. Thiên Vận tử là người đầu tiên nhận ra đoàn người đã tới, sau đó các đại thần thông khác cũng lần lượt chú ý về phía tinh không xa. Lôi Cát xuất hiện với thân hình Cự Ma Tộc khổng lồ và dấu ấn hoàng tộc, khiến đám đông kinh ngạc về thân phận người cưỡi. Trên lưng Lôi Cát, Trần Đạo Tam Tử, Đồng tử đầu to, Phù Phong tử, Ngân Y Luyện Thi, Tư Đồ Nam rồi Vương Lâm lần lượt lộ diện, tạo thành đội hình bốn Khuy Niết và ba Tịnh Niết gây chấn động. Vương Lâm bình thản chào Thiên Vận tử, Lăng Thiên Hậu cùng các đại thần thông, còn Lăng Thiên Hậu đổi cách xưng hô và gọi hắn là đạo hữu. Tinh Ngân Điêu trên vai Tôn Thiện phản ứng kỳ dị khi thấy Vương Lâm nhưng nhanh chóng trở lại bình thường. Khi người đã đủ, Thiên Vận tử dùng lệnh bài bảy màu mở Đông Hải Triều tịch, tuyên bố sẽ mở động phủ thứ năm và đi trước vào hố đen. Trước lúc tiến vào, Vương Lâm nhận ra cây đinh ba của Thiên Vận tử có khí tức quen thuộc và gần như xác định đó là pháp bảo do Đồ Ti luyện chế năm xưa."},{"chuong":938,"tieuDe":"Hư Không Tử","tomTat":"Cây đinh ba mà Thiên Vận Tử mang vào hố đen được hé lộ là pháp bảo năm xưa Đồ Ti từng dùng cả một tinh cầu để dưỡng linh, khiến Vương Lâm nhìn theo mà sinh ra cảm giác tiếc nuối từ ký ức Cổ thần. Trước khi các tu sĩ tiến vào vùng đất Yêu Linh, Hư Không Tử xuất hiện với thân phận Đại trưởng lão, được Lăng Thiên Hậu và Tôn Thiện cung kính bái kiến; khí tức Toái Niết của ông khiến Vương Lâm kinh hãi, còn Tư Đồ Nam cũng bị chấn động. Hư Không Tử nhắc lại duyên cũ khi từng đưa Lăng Thiên Hậu và Thiên Vận Tử vào Côn Hư, đồng thời nói rõ mình nhận ngọc giản của Lăng Thiên Hậu nên đến để chấm dứt ân oán giữa hai người dù chiến sự với La Thiên đang căng thẳng. Sau đó Hư Không Tử dẫn đầu vào hố đen, các nhóm Vương Lâm, Tư Đồ Nam, Phù Phong Tử, Lôi Cát, nhóm nữ tu của Tịch Huyên và nhiều tu sĩ khác lần lượt theo sau; cửa vào nhanh chóng xoay ngược biến mất, nghiền chết những kẻ còn mắc kẹt bên ngoài. Trong vùng đất Yêu Linh, quận Hỏa Yêu đã bị chiến tranh tàn phá, các thế lực nhỏ tan rã, chỉ còn đô thành Hỏa Yêu do Hỏa Yêu Linh quân cố thủ trước vòng vây của bộ lạc Luyện Hồn. Âu Dương Hoa ép Mộc Vận và Hạt Kim đầu hàng, nhưng Hạt Kim lao ra định phá tượng đá Lão tổ thì bị Thập Tam một quyền đánh nát, khiến phòng tuyến tinh thần của đô thành sụp đổ. Khi Âu Dương Hoa phát lệnh Hồn diệt, nữ tử mặc giáp xanh trên thành buộc phải tuyên bố quy hàng, quận Hỏa Yêu chính thức trở thành đô thành của bộ lạc Luyện Hồn. Đúng lúc tượng đá Lão tổ chuẩn bị được đưa vào vị trí Linh hồn Cổ Yêu ngày trước, Thập Tam bỗng run rẩy, cảm ứng được Lão tổ đã trở lại."},{"chuong":939,"tieuDe":"Sự Thù Hận Của Diêu Tích Huyết","tomTat":"Yêu Linh chi địa bị vô số lốc xoáy bao phủ, khiến các tồn tại ẩn giấu trong vùng đồng loạt bị kinh động, trong đó có một khuôn mặt yêu dị dưới hồ ở Mộc Yêu Quận đã chờ ngày này từ lâu. Ở khu Tiên phủ, Vương Nguy và Hồ Quyên nhận ra thời cơ kế hoạch nhiều năm đã đến, đồng thời nhắc tới Tiên giới chi trận, cơ chế năm Tiên phủ và kiếm linh đang tu Bất diệt linh quyết đến tầng cao. Dưới Hoàng cung Phong Yêu Quận, Diêu Tích Tuyết vì hận Vương Lâm và vì cảm ứng phụ thân dữ nhiều lành ít mà chấp nhận truyền thừa Phong Yêu, chịu thi khí hủy hoại dung nhan, thần thức và linh hồn để đổi lấy lực lượng báo thù. Vương Lâm cùng Tư Đồ Nam và các tu sĩ bước vào Yêu Linh chi địa; hắn thoáng cảm nhận oán khí ngập trời từ hướng Phong Yêu Quận nhưng tạm gác lại. Sau đó Vương Lâm giao thạch bàn và chỉ dẫn cấm chế Tiên phủ thứ tư cho Tư Đồ Nam dẫn người đi phá cấm, còn bản thân muốn trở lại thăm Luyện Hồn bộ lạc và những cố nhân năm xưa. Khi thần thức của hắn bao trùm Yêu Linh chi địa, tượng đá Lão Tổ của Luyện Hồn bộ lạc phát ra hắc quang cộng minh, cho hắn thấy sức tín ngưỡng cuồng nhiệt tích lũy qua mấy trăm năm. Vương Lâm hiện thân trên bầu trời Hỏa Yêu Quận, được Âu Dương Hoa, Thập Tam và hàng trăm vạn tộc nhân quỳ bái nghênh đón, rồi tuyên bố mình đã trở về sau nhiều năm xa cách."},{"chuong":940,"tieuDe":"Tượng Đá Màu Đen Quỷ Dị","tomTat":"Vương Lâm trở về Hỏa Yêu Quận, xóa tên cũ và chính thức biến cơ nghiệp Luyện Hồn bộ lạc thành Luyện Hồn Tông với hơn trăm vạn đệ tử cùng vô số hồn phách trong Hồn Phiên. Hắn nhìn trời nhớ tới Độn Thiên, xác nhận lời hứa năm xưa đã hoàn thành, rồi bắt đầu truyền pháp cho tông môn bằng Cửu Chuyển Luyện Tiên quyết, các Tiên thuật trong Tàng Phẩm Các và hệ cấm pháp phù hợp hồn phách. Âu Dương Hoa được ban Luyện Hồn Thành Tiên và được giao an bài Tàng Bảo Các, còn Thập Tam được Vương Lâm rèn thân bằng máu Lôi Cát Cự Ma Tộc, máu vương tộc Cổ Thần và pháp bảo dung nhập thân thể, đạt gần cảnh giới Tiên vệ Ngân Thi nhưng vẫn giữ thần trí. Vương Lâm xác nhận Thập Tam là đại đệ tử, Tạ Thanh là nhị đệ tử, rồi truyền cho Thập Tam Tiên Phách thuật. Sau khi hoàn thành việc dựng nền tông môn, hắn một mình tới thung lũng sau hoàng cung, nơi từng phóng xuất Cổ Yêu Bối La nuốt Hỏa Yêu Linh. Tại đó, tượng đá màu đen ban đầu do Thập Tam khắc thô theo trí nhớ nay đã qua mấy trăm năm cúng bái mà trở nên giống Vương Lâm như đúc, có cả ánh mắt linh động và vẻ tang thương. Vương Lâm cảm thấy tượng đang nhìn lại mình, xung quanh như biến mất chỉ còn hắn và tượng, nên đưa ngón trỏ phải tới mi tâm tượng để dò xét."},{"chuong":941,"tieuDe":"Phân Thân Thứ Hai","tomTat":"Vương Lâm thăm dò bức tượng đá màu đen của Luyện Hồn Tông thì bị phù văn trên mi tâm tượng phản kích, một luồng lực lượng quỷ dị như mực nước xâm nhập nguyên thần hắn. Hắn lập tức vận Cổ Thần bì giáp phong bế đường lui, đồng thời mượn nguyên thần Thái Cổ Lôi Long dẫn động lôi đình trên hơn phân nửa Yêu Linh chi địa, cưỡng ép đánh tan nguy cơ này. Sau khi phá được phù văn, Vương Lâm đưa thần thức vào trong tượng và phát hiện một không gian đầy yêu khí cúng bái, nơi có một Cổ Yêu mang dung mạo giống hệt hắn nhưng trên đầu mọc hai sừng. Qua sưu tra ký ức, hắn hiểu đó là tia Yêu Thức còn sót của Vân Yêu, sau khi trốn vào tượng đá đã bị tín niệm nhiều đời tộc nhân Luyện Hồn bộ lạc cải biến, dần quên đi quá khứ và tự nhận mình là Vương Lâm. Nhận ra đây là cơ duyên hiếm có, Vương Lâm quyết định tế luyện tia Yêu Thức này thành phân thân thứ hai, lấy bản tôn Cổ Thần, phân thân tu sĩ và phân thân Cổ Yêu làm nền cho con đường tu luyện về sau. Hắn nhiều ngày dung nhập thần thức, đặt lạc ấn phản chế và thi triển thêm thuật khống chế khôi lỗi từng dùng với Thanh Lâm, bảo đảm phân thân hoàn toàn chịu sự chi phối của mình rồi để lại trong Luyện Hồn Tông tiếp tục hấp thu yêu khí cúng bái. Rời Hỏa Yêu Quận, Vương Lâm trở lại Cực Thành của Thiên Yêu Quận, ngồi bên dòng sông cũ mà cảm nhận cảnh vật đổi thay, rượu xưa cũng không còn đúng vị trong ký ức. Đúng lúc ấy Đế Quân xuất hiện với rượu năm đó đã cất giữ để chờ hắn, rồi trên sông vang lên tiếng đàn và một con thuyền lớn hiện ra, gợi lại cảnh cố nhân thuở trước."},{"chuong":942,"tieuDe":"Ủy Thác Của Đế Quân","tomTat":"Vương Lâm và Đế Quân uống rượu bên sông trong tiếng đàn gợi lại chuyện cũ, nhưng người đánh đàn hiện tại không phải manh nữ năm xưa. Sáng hôm sau, Đế Quân truyền lời Bối La: nếu Vương Lâm giữ một danh ngạch vào Tiên phủ thứ năm, Bối La sẽ giao bốn Quận trong chín Quận Yêu Linh chi địa cho Luyện Hồn bộ lạc và không can thiệp chuyện Yêu Thức Vân Yêu còn sót lại. Đế Quân tiếp đó nhờ Vương Lâm mang Đế Kiếm chi linh rời Yêu Linh chi địa để nàng tiến nhập luân hồi, còn Vương Lâm nhận ra thọ hạn của ông đã gần hết nên đồng ý. Đế Quân triệu Đế Kiếm tới, từ biệt thiếu nữ kiếm linh; nàng đau buồn nhập lại vào Đế Kiếm rồi đi theo Vương Lâm, được hắn thu vào túi trữ vật. Vương Lâm mở Tiên phủ ngọc giản trở lại Tiên phủ thứ tư, nơi Tư Đồ Nam dẫn nhóm phá cấm đã tới ranh giới Nội phủ nhưng bị cấm chế cầu đá cản lại. Tư Đồ Nam mất kiên nhẫn rời nhóm đi dò bảo trong rừng trúc, còn Phù Phong Tử giải thích thế cấm hình chữ Hồi và lo cưỡng ép phá giải sẽ sinh biến. Vương Lâm nhận ra cấm chế trước cầu khác hẳn bên ngoài và có sát khí, bèn gọi Ngân y nữ tử tới, lệnh nàng tiến vào mười bước để thử nghiệm."},{"chuong":943,"tieuDe":"Sâu Bên Trong Tiên Phủ","tomTat":"Ba người Trần Đạo Tam Tử tỉnh lại sau khi hấp thu tiên khí, Nhất Trần Tử nhận ra khu vực trước mặt tuy bình tĩnh nhưng ẩn sát khí nên khuyên Vương Lâm nếu muốn cưỡng phá thì cần mọi người cùng ra tay. Vương Lâm không chọn cách đó mà sai Ngân Y Luyện Thi bước vào phạm vi trăm bước để thử cấm, rồi chỉ điểm nàng đánh vào kiền vị bên trái nhằm phá biến hóa đầu tiên. Sau đó hắn tự bước vào cấm chế, nhận ra nơi này khác tử cấm bên ngoài, có hàng vạn cấm chế liên kết và quy về hai hình thái bùn đất, thủy khí. Dựa vào nền tảng cấm chế từ Cổ Thần chi địa, Phá Diệt Cấm và Tâm Cấm Thuật, Vương Lâm lấy cấm phá cấm, vượt qua trần bạo đen rồi dùng Tâm Cấm la bàn phá thủy khí sóng dữ. Tiếng rít từ trong Tiên phủ vang lên khiến hắn xác nhận cấm chế trăm bước đang bị người hoặc vật thao khống. Vương Lâm cầm la bàn xông lên cầu đá, Phù Phong Tử, Trần Đạo Tam Tử và Đại Đầu đi theo vào sâu bên trong. Nhóm người nhìn thấy không gian trong Tiên phủ như hoa viên, có lầu các, đại điện điêu long khắc phượng, Tiên thú lạ và mười kim tượng mặc giáp. Vương Lâm nhận ra các kim tượng làm từ huyền kim, tài liệu tăng cường thân thể Tiên vệ theo ngọc giản Tiên Đế Thanh Lâm, trong khi một cỗ uy nghiêm đáng sợ từ đại điện lan ra."},{"chuong":944,"tieuDe":"Hoa Tiên","tomTat":"Phù Phong Tử nhắc lại lời Lăng Thiên Hầu rằng trong Tiên phủ có Tiên hồn thủ hộ, rồi Vương Lâm lập tức vượt cầu đá tiến sâu vào trong. Hoa viên phía trước chuyển động và tỏa Vũ hậu độc hương, một loại kỳ độc của Vũ chi Tiên giới có thể khiến tu vi không thuận hoặc phế bỏ tu vi. Vương Lâm thử dùng gió xua độc không thành nên gọi ngân thi ra hút độc, đồng thời chương xác nhận sức mạnh chân chính của ngân thi nằm ở độc tố dung hợp trong thi thể. Khi độc hương bị hút, các đóa hoa hiện thành hư ảnh thiếu nữ và để lộ hài cốt nhỏ bé dưới bùn, khiến cả hoa viên giống một nghĩa địa. Phù Phong Tử giải thích Hoa Linh và Hoa Tiên đều là độc vật, trong đó Hoa Tiên xếp thứ mười và có nguồn gốc từ phương pháp luyện nữ đồng trinh thành dược nhân rồi mai táng tập thể. Ngân thi dùng sương trắng phá tan Hoa Linh, làm hoa cỏ héo rũ và khiến tiếng kêu bén nhọn vang lên từ đại điện. Mười Tôn Tiên binh hóa kim quang lao ra ngăn nàng hấp thu, còn Phù Phong Tử, Trần Đạo Tam Tử, Đại Đầu và Nhất Trần Tử lần lượt ra tay chặn chúng."},{"chuong":945,"tieuDe":"Nguy Cơ","tomTat":"Nhất Long Tử, Nhất Tinh Tử và Phù Phong Tử lần lượt chế trụ các Tiên binh, giúp Vương Lâm có đường tiến về đại điện trong Tiên phủ. Khi hắn tới gần, lầu các quanh đại điện biến ảo, hợp thành quy xác phòng hộ, đồng thời bốn hồn thể áo xanh xuất hiện và dùng Tiên thuật hóa cự viên, hắc mãng, đại điêu, tiên sơn để vây sát hắn. Vương Lâm lần lượt dùng quyền lực Cổ Thần, Tử mẫu đạo khô, Tam cửu chi kiếm và Phong Tiên Ấn phá thế liên kích, rồi thi triển Hô phong hóa bốn hắc long nuốt bốn hồn thể; lão cuối cùng còn bị Định Thân thuật khóa lại trước khi bị diệt. Sau đó hắn dùng Cổ Thần Tí đánh quy xác nhưng không phá nổi, Phù Phong Tử cùng mọi người liên thủ cũng chỉ khiến lớp phòng hộ ảm đạm, trong khi cầu đá xa xa sụp đổ. Ngân thi sau khi hấp thu hoa linh có biến hóa kỳ dị và không bị ảnh hưởng bởi tiếng bước chân trong đại điện vì là thi thể có linh tính. Khi quy xác phát sáng lộ đại điện u ám, tiếng bước chân bên trong kéo nhịp tim mọi người theo tần suất kỳ dị, khiến Trần Đạo Tam Tử, Đại Đầu và Lôi Cát lần lượt lộ vẻ chống đỡ khó khăn. Cuối chương, một bóng dáng màu trắng bước ra từ chỗ tối, ánh mắt xuyên qua mai rùa nhìn Vương Lâm, khiến hắn cảm nhận nguy cơ sinh tử dữ dội."},{"chuong":946,"tieuDe":"Cảnh Cáo","tomTat":"Trong đại điện Tiên phủ, bóng dáng nữ tử áo trắng xuất hiện và chỉ một ánh mắt đã khiến Vương Lâm phun máu, còn Phù Phong Tử, Trần Đạo Tam Tử, Đại Đầu và Lôi Cát đều bị trọng thương tâm thần. Vương Lâm hiểu đó là lời cảnh cáo không được bước vào, nhưng hắn vẫn quyết tiến tiếp vì Chu Dật chưa rõ sống chết, Thanh Sương cần Thanh Lâm phục sinh và độc của Tư Đồ Nam cần được giải. Hắn triệu Diệt Thần Mâu, vận Cổ Thần lực Ngũ tinh vương tộc, lệnh Phù Phong Tử và ngân thi cùng ra tay phá lớp mai rùa chắn trước thông đạo. Dưới hợp kích của bia đá kim quang, khói nhiều màu và Diệt Thần Mâu, mai rùa hoàn toàn sụp đổ. Nữ tử áo trắng, được Phù Phong Tử gọi là Hoa Tiên, dùng hoa tím hồng chặn Diệt Thần Mâu và hóa khói nhiều màu của ngân thi thành hoa. Khi nàng tiếp tục ra tay, Vương Lâm phun ra Lôi chi Tiên giới Toái phiến để phòng hộ, nhưng pháp bảo hộ mệnh do Viêm Lôi Tử ban tặng bị các đóa hoa đánh vỡ tứ phân ngũ liệt."},{"chuong":947,"tieuDe":"Táng Hoa","tomTat":"Sau khi Tiên giới Toái phiến sụp đổ, kỳ hương từ nữ tử áo trắng đánh thẳng vào Vương Lâm khiến hắn trọng thương, phải dựa vào thân thể Cổ Thần và Thanh quang thuẫn để sống sót. Nữ tử áo trắng tiếp tục dùng rừng hoa phong kín Phù Phong Tử, Trần Đạo Tam Tử, Đại Đầu và ngân thi, khiến nhóm đồng hành lần lượt biến mất trong kỳ hương. Nàng tháo trâm cài tóc tấn công rồi thi triển Táng hoa, biến cả động phủ thành thế giới hoa héo rũ muốn chôn vùi Vương Lâm. Trong tuyệt cảnh, Vương Lâm lần đầu đồng thời thi triển Hô phong, Hoán vũ và Tản đậu thành binh, phối hợp Phong Tiên Ấn gọi ra chiến hồn để phá mở rừng hoa. Nữ tử áo trắng dùng quang đoàn chứa bổn nguyên lực làm tổ hợp ba Tiên thuật thoái hóa và tan rã, buộc Vương Lâm mở con mắt thứ ba dùng bổn nguyên lực triệt tiêu. Thấy hắn có Cổ Thần, Tiên thuật của Bạch Phàm và bổn nguyên lực, nàng dừng truy kích chất vấn thân phận. Vương Lâm quyết đánh cược, thi triển Định Thân thuật rồi lấy Tiên ngọc tháp chứa thi thể Thanh Ải ra, khiến nữ tử áo trắng chấn động như bị sét đánh."}];
